const metaParameterFieldsByEvent: Record<string, SiteMetaParameterFieldKey[]> = {
  Lead: ['value', 'predictedLtv'],
  Schedule: ['value', 'predictedLtv'],
  FormSubmitted: ['value', 'predictedLtv'],
  CompleteRegistration: ['value', 'predictedLtv'],
  Contact: ['value', 'predictedLtv'],
  Purchase: ['value', 'orderId', 'contentIds', 'contentName', 'contentType', 'numItems'],
  ViewContent: ['value', 'contentName', 'contentCategory', 'contentIds', 'contentType']
}

const getMetaParameterFieldsForEvent = (eventName?: string): SiteMetaParameterFieldKey[] =>
  metaParameterFieldsByEvent[normalizeMetaEventName(eventName, 'none')] || []

const cleanMetaParameterString = (value: unknown) => String(value ?? '').trim()

const normalizeMetaCustomParameter = (parameter?: Partial<SiteMetaCustomParameter> | null): SiteMetaCustomParameter => ({
  ...(cleanMetaParameterString(parameter?.id) ? { id: cleanMetaParameterString(parameter?.id) } : {}),
  key: cleanMetaParameterString(parameter?.key).replace(/[^a-zA-Z0-9_]/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '').slice(0, 64),
  value: cleanMetaParameterString(parameter?.value)
})

const normalizeMetaEventParameters = (parameters?: SiteMetaEventParameters | null): SiteMetaEventParameters => {
  const source = parameters && typeof parameters === 'object' ? parameters : {}
  const normalized: SiteMetaEventParameters = {}

  Object.keys(metaParameterFieldLabels).forEach((fieldKey) => {
    const key = fieldKey as SiteMetaParameterFieldKey
    const value = cleanMetaParameterString(source[key])
    if (value) {
      normalized[key] = value
    }
  })

  const custom = Array.isArray(source.custom)
    ? source.custom
      .map(normalizeMetaCustomParameter)
      .filter(parameter => parameter.key || parameter.value)
      .slice(0, 12)
    : []

  if (custom.length) normalized.custom = custom
  return normalized
}

const hasMetaEventParameters = (parameters?: SiteMetaEventParameters | null) => {
  const normalized = normalizeMetaEventParameters(parameters)
  return Object.keys(metaParameterFieldLabels).some(fieldKey => Boolean(cleanMetaParameterString(normalized[fieldKey as SiteMetaParameterFieldKey]))) ||
    Boolean(normalized.custom?.some(parameter => parameter.key || parameter.value))
}

const pruneMetaEventParametersForEvent = (parameters?: SiteMetaEventParameters | null, eventName?: string): SiteMetaEventParameters => {
  const normalized = normalizeMetaEventParameters(parameters)
  const fields = getMetaParameterFieldsForEvent(eventName)
  if (!fields.length) return {}
  const allowed = new Set(fields)
  const pruned: SiteMetaEventParameters = {}

  allowed.forEach((key) => {
    const value = cleanMetaParameterString(normalized[key])
    if (value) pruned[key] = value
  })

  if (normalized.custom?.length) pruned.custom = normalized.custom
  return pruned
}

const metaParameterVariableCategories = new Set([
  'contact',
  'custom',
  'variable',
  'form',
  'appointment',
  'payment',
  'conversation',
  'automation'
])

const toMetaParameterVariable = (variable: FlowVariable): MetaParameterVariable => ({
  fieldId: variable.fieldId,
  label: variable.label,
  category: variable.category,
  categoryLabel: variable.categoryLabel
})

const sanitizeMetaVariablePathSegment = (value: unknown, fallback = 'campo') => {
  const normalized = String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
  return normalized || fallback
}

const getMetaFormFieldVariableKey = (block: SiteBlock) => {
  const settings = block.settings || {}
  return sanitizeMetaVariablePathSegment(
    settings.customFieldKey ||
    settings.custom_field_key ||
    settings.internalName ||
    settings.internal_name ||
    settings.systemFieldKey ||
    settings.system_field_key ||
    block.label ||
    block.content ||
    block.placeholder ||
    block.id,
    block.id || 'campo'
  )
}

const findMetaFormSource = (forms: PublicSite[] = [], sourceId?: string) => (
  sourceId ? forms.find(form => form.id === sourceId) || null : null
)

const collectSiteMetaFormFieldBlocks = (
  site?: PublicSite | null,
  forms: PublicSite[] = [],
  visitedFormIds = new Set<string>()
): SiteBlock[] => {
  const output: SiteBlock[] = []
  const visitBlocks = (blocks: SiteBlock[] = []) => {
    blocks.forEach((block) => {
      if (fieldBlockTypes.has(block.blockType)) output.push(block)

      const nestedBlocks = Array.isArray(block.settings?.embeddedBlocks)
        ? block.settings.embeddedBlocks as SiteBlock[]
        : []
      if (nestedBlocks.length) visitBlocks(nestedBlocks)

      const linkedFormId = block.blockType === 'form_embed'
        ? getEmbeddedFormSourceId(block)
        : block.blockType === 'video'
          ? getVideoFormGateSourceId(block)
          : ''
      if (!linkedFormId || visitedFormIds.has(linkedFormId)) return

      const linkedForm = findMetaFormSource(forms, linkedFormId)
      if (!linkedForm) return
      visitedFormIds.add(linkedFormId)
      visitBlocks(linkedForm.blocks || [])
    })
  }

  visitBlocks(site?.blocks || [])
  return output
}

const buildSiteFormMetaParameterVariables = (site?: PublicSite | null, forms: PublicSite[] = []): MetaParameterVariable[] => (
  collectSiteMetaFormFieldBlocks(site, forms)
    .sort((left, right) => Number(left.sortOrder || 0) - Number(right.sortOrder || 0))
    .flatMap((block) => {
      const label = String(block.label || block.content || block.placeholder || blockLabels[block.blockType] || 'Campo').trim()
      const fieldKey = getMetaFormFieldVariableKey(block)
      const variables: MetaParameterVariable[] = [{
        fieldId: `form.responses.${fieldKey}`,
        label: `Respuesta: ${label}`,
        category: 'form',
        categoryLabel: 'Formulario'
      }, {
        fieldId: `form.responses.${fieldKey}.value`,
        label: `Valor interno: ${label}`,
        category: 'form',
        categoryLabel: 'Formulario'
      }, {
        fieldId: `form.responses.${fieldKey}.text`,
        label: `Texto visible: ${label}`,
        category: 'form',
        categoryLabel: 'Formulario'
      }]
      if (block.id) {
        variables.push({
          fieldId: `form.answers_by_id.${block.id}`,
          label: `${label} (ID)`,
          category: 'form',
          categoryLabel: 'Formulario'
        }, {
          fieldId: `form.answers_by_id.${block.id}.value`,
          label: `Valor interno: ${label} (ID)`,
          category: 'form',
          categoryLabel: 'Formulario'
        }, {
          fieldId: `form.answers_by_id.${block.id}.text`,
          label: `Texto visible: ${label} (ID)`,
          category: 'form',
          categoryLabel: 'Formulario'
        })
      }
      return variables
    })
)

const useMetaParameterVariables = (site?: PublicSite | null, forms: PublicSite[] = []) => {
  const [loadedVariables, setLoadedVariables] = useState<FlowVariable[]>(BASE_VARIABLES)

  useEffect(() => {
    let cancelled = false
    void loadAllVariables().then((variables) => {
      if (!cancelled) setLoadedVariables(variables)
    })
    return () => { cancelled = true }
  }, [])

  return useMemo(() => {
    const variables = [
      ...loadedVariables
        .filter(variable => metaParameterVariableCategories.has(variable.category))
        .map(toMetaParameterVariable),
      ...buildSiteFormMetaParameterVariables(site, forms)
    ]
    const seen = new Set<string>()
    return variables.filter((variable) => {
      if (!variable.fieldId || seen.has(variable.fieldId)) return false
      seen.add(variable.fieldId)
      return true
    })
  }, [forms, loadedVariables, site])
}

