const IMPORTED_TEXT_FONT_SIZE_MIN = 10
const IMPORTED_TEXT_FONT_SIZE_MAX = 96
const IMPORTED_CODE_PANEL_COLLAPSE_THRESHOLD = 6
const IMPORTED_CODE_PANEL_MIN_WIDTH = 24
const IMPORTED_CODE_PANEL_MAX_WIDTH = 88
const IMPORTED_CODE_PANEL_DEFAULT_WIDTH = 50
const IMPORTED_CODE_PANEL_INSPECTOR_MAX_WIDTH = 38

const clampImportedTextFontSize = (value: number, fallback = 16) => {
  const numericValue = Number.isFinite(value) ? value : fallback
  return Math.min(IMPORTED_TEXT_FONT_SIZE_MAX, Math.max(IMPORTED_TEXT_FONT_SIZE_MIN, Math.round(numericValue)))
}

const normalizeImportedCodePanelWidth = (value: number) => {
  if (!Number.isFinite(value) || value <= IMPORTED_CODE_PANEL_COLLAPSE_THRESHOLD) return 0
  return Math.min(IMPORTED_CODE_PANEL_MAX_WIDTH, Math.max(IMPORTED_CODE_PANEL_MIN_WIDTH, value))
}

const getImportedCodePanelSourceWidth = (value: number, hasInspector: boolean) => {
  if (value <= 0) return 0
  return hasInspector ? Math.min(value, IMPORTED_CODE_PANEL_INSPECTOR_MAX_WIDTH) : value
}

const getImportedCodePanelSourceTrack = (value: number, hasInspector: boolean) => {
  const width = getImportedCodePanelSourceWidth(value, hasInspector)
  if (width <= 0) return '0px'
  return `minmax(${hasInspector ? '300px' : '340px'}, ${width}%)`
}

const normalizeImportedNativeToken = (value?: string | null) => (
  String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[_\s]+/g, '-')
)

const normalizeImportedContentAssetKey = (value?: string | null) => (
  String(value || '')
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80)
)

const getImportedContentAssetAttr = (element: Element, names: string[]) => {
  for (const name of names) {
    const value = element.getAttribute(name)
    if (value !== null && String(value).trim()) return String(value).trim()
  }
  return ''
}

const getImportedContentAssetKeyFromElement = (element: Element) => normalizeImportedContentAssetKey(
  getImportedContentAssetAttr(element, [
    'data-rstk-background-asset-id',
    'data-ristak-background-asset-id',
    'data-ristack-background-asset-id',
    'data-rstk-asset-id',
    'data-ristak-asset-id',
    'data-ristack-asset-id'
  ])
)

const getImportedContentAssetTargetFromElement = (element: Element) => {
  const tagName = element.tagName.toLowerCase()
  const explicitTarget = normalizeImportedNativeToken(getImportedContentAssetAttr(element, [
    'data-rstk-asset-target',
    'data-ristak-asset-target',
    'data-ristack-asset-target'
  ]))
  const supportsSrc = ['img', 'video', 'audio', 'source', 'track', 'iframe'].includes(tagName) || (
    tagName === 'input' && normalizeImportedNativeToken(element.getAttribute('type')) === 'image'
  )

  if (explicitTarget) {
    if (explicitTarget === 'href' && tagName === 'a') return 'href'
    if (explicitTarget === 'poster' && tagName === 'video') return 'poster'
    if (explicitTarget === 'src' && supportsSrc) return 'src'
    return ''
  }
  if (tagName === 'a') return 'href'
  return supportsSrc ? 'src' : ''
}

const getImportedContentAssetKindFromElement = (element: Element): ImportedContentAssetKind => {
  const isBackground = Boolean(getImportedContentAssetAttr(element, [
    'data-rstk-background-asset-id',
    'data-ristak-background-asset-id',
    'data-ristack-background-asset-id'
  ]))
  if (isBackground) return 'background'

  const tagName = element.tagName.toLowerCase()
  if (getImportedContentAssetTargetFromElement(element) === 'poster') return 'image'
  if (tagName === 'img' || (tagName === 'input' && normalizeImportedNativeToken(element.getAttribute('type')) === 'image')) return 'image'
  if (tagName === 'audio') return 'audio'
  if (tagName === 'video' || tagName === 'iframe') return 'video'
  if (tagName === 'source') {
    const parentTag = element.parentElement?.tagName.toLowerCase()
    if (parentTag === 'audio') return 'audio'
    if (parentTag === 'video' || parentTag === 'picture') return parentTag === 'picture' ? 'image' : 'video'
  }
  if (tagName === 'a') return 'document'
  const explicitKind = normalizeImportedNativeToken(getImportedContentAssetAttr(element, [
    'data-rstk-asset-kind',
    'data-ristak-asset-kind',
    'data-ristack-asset-kind'
  ]))
  if (['image', 'imagen', 'photo', 'foto', 'background', 'fondo', 'background-image'].includes(explicitKind)) return 'image'
  if (['audio', 'sound', 'sonido'].includes(explicitKind)) return 'audio'
  if (['video', 'player', 'reproductor'].includes(explicitKind)) return 'video'
  if (['document', 'documento', 'download', 'descarga', 'file', 'archivo', 'pdf'].includes(explicitKind)) return 'document'
  return 'other'
}

const getImportedContentAssetLabel = (element: Element, kind: ImportedContentAssetKind, assetKey: string) => {
  const explicitLabel = getImportedContentAssetAttr(element, [
    'data-rstk-label',
    'data-ristak-label',
    'data-ristack-label',
    'aria-label',
    'title',
    'alt'
  ])
  if (explicitLabel) return explicitLabel
  const text = String(element.textContent || '').replace(/\s+/g, ' ').trim()
  if (text) return text.slice(0, 80)
  return `${importedContentAssetKindLabels[kind]} ${assetKey}`
}

const detectImportedContentAssetSlots = (html = ''): ImportedContentAssetSlot[] => {
  if (!html || typeof DOMParser === 'undefined') return []
  try {
    const doc = new DOMParser().parseFromString(html, 'text/html')
    const slots = new Map<string, ImportedContentAssetSlot>()
    Array.from(doc.querySelectorAll(importedContentAssetSelector)).forEach(element => {
      const assetKey = getImportedContentAssetKeyFromElement(element)
      if (!assetKey) return
      const isBackground = Boolean(getImportedContentAssetAttr(element, [
        'data-rstk-background-asset-id',
        'data-ristak-background-asset-id',
        'data-ristack-background-asset-id'
      ]))
      if (!isBackground && !getImportedContentAssetTargetFromElement(element)) return
      const kind = getImportedContentAssetKindFromElement(element)
      const existing = slots.get(assetKey)
      if (existing) {
        slots.set(assetKey, {
          ...existing,
          kind: existing.kind === 'other' ? kind : existing.kind,
          occurrences: existing.occurrences + 1
        })
        return
      }
      slots.set(assetKey, {
        key: `asset:${assetKey}`,
        assetKey,
        kind,
        label: getImportedContentAssetLabel(element, kind, assetKey),
        tagName: element.tagName.toLowerCase(),
        occurrences: 1
      })
    })
    return [...slots.values()]
  } catch {
    return []
  }
}

const normalizeImportedNativeElementType = (value?: string | null): ImportedNativeElementType | null => {
  const token = normalizeImportedNativeToken(value)
  if (['form', 'forms', 'formulario', 'formularios', 'lead-form', 'lead'].includes(token)) return 'form'
  if (['calendar', 'calendars', 'calendario', 'calendarios', 'agenda', 'cita', 'citas', 'booking', 'appointment', 'appointments'].includes(token)) return 'calendar'
  if (['payment', 'payments', 'pago', 'pagos', 'checkout', 'cobro', 'cobros', 'purchase'].includes(token)) return 'payment'
  if (['video', 'videos', 'video-player', 'player', 'reproductor', 'media'].includes(token)) return 'video'
  if (['social-profile', 'social-profiles', 'perfil-social', 'perfiles-sociales', 'red-social', 'social', 'profile'].includes(token)) return 'social_profile'
  return null
}

const getImportedNativeElementAttr = (element: Element, names: string[]) => {
  for (const name of names) {
    const value = element.getAttribute(name)
    if (value !== null && String(value).trim()) return String(value).trim()
  }
  return ''
}

const getImportedNativeElementTypeFromElement = (element: Element): ImportedNativeElementType | null => (
  normalizeImportedNativeElementType(getImportedNativeElementAttr(element, [
    'data-rstk-native-element',
    'data-ristak-native-element',
    'data-ristack-native-element',
    'data-rstk-element',
    'data-ristak-element',
    'data-ristack-element',
    'data-rstk-element-type',
    'data-ristak-element-type',
    'data-ristack-element-type',
    'data-rstk-component',
    'data-ristak-component',
    'data-ristack-component',
    'data-rstk-widget',
    'data-ristak-widget',
    'data-ristack-widget'
  ]))
)

const isImportedCalendarBookingFormElement = (form: HTMLFormElement) => {
  if ([
    'data-rstk-calendar-book-form',
    'data-ristak-calendar-book-form',
    'data-ristack-calendar-book-form'
  ].some(name => form.hasAttribute(name))) return true

  let element: Element | null = form.parentElement
  while (element) {
    if (getImportedNativeElementTypeFromElement(element) === 'calendar') return true
    if (normalizeImportedNativeElementType(element.getAttribute('data-rstk-native-type')) === 'calendar') return true
    element = element.parentElement
  }
  return false
}

const getImportedNativeElementRenderMode = (element: Element, type: ImportedNativeElementType): ImportedNativeElementRenderMode => {
  if (type !== 'calendar' && type !== 'social_profile') return 'ristak'
  const token = normalizeImportedNativeToken(getImportedNativeElementAttr(element, [
    'data-rstk-native-render',
    'data-ristak-native-render',
    'data-ristack-native-render',
    'data-rstk-render',
    'data-ristak-render',
    'data-ristack-render',
    'data-rstk-calendar-render',
    'data-ristak-calendar-render',
    'data-ristack-calendar-render'
  ]))
  return ['custom', 'propio', 'own', 'external', 'externo', 'html', 'mapped', 'mapeado'].includes(token) ? 'custom' : 'ristak'
}

const getImportedNativeElementSlotId = (element: Element, type: ImportedNativeElementType, index: number) => {
  const explicitId = getImportedNativeElementAttr(element, [
    'data-rstk-native-id',
    'data-ristak-native-id',
    'data-ristack-native-id',
    'data-rstk-element-id',
    'data-ristak-element-id',
    'data-ristack-element-id',
    'data-rstk-edit-id',
    'data-ristak-edit-id',
    'data-ristack-edit-id',
    'id'
  ])
  return explicitId || `${type}-${index + 1}`
}

const getImportedNativeElementExplicitSlotId = (element: Element) => getImportedNativeElementAttr(element, [
  'data-rstk-native-id',
  'data-ristak-native-id',
  'data-ristack-native-id',
  'data-rstk-element-id',
  'data-ristak-element-id',
  'data-ristack-element-id',
  'data-rstk-edit-id',
  'data-ristak-edit-id',
  'data-ristack-edit-id',
  'id'
])

const findImportedNativeElementFromTarget = (
  target: Element | null,
  slots: ImportedNativeElementSlot[]
): { slot: ImportedNativeElementSlot; element: HTMLElement } | null => {
  if (!target || typeof target.closest !== 'function' || !slots.length) return null
  const element = target.closest(importedNativeElementSelector) as HTMLElement | null
  if (!element) return null
  const type = getImportedNativeElementTypeFromElement(element)
  if (!type) return null

  const explicitId = getImportedNativeElementExplicitSlotId(element)
  const exactSlot = explicitId ? slots.find(slot => slot.type === type && slot.id === explicitId) : null
  if (exactSlot) return { slot: exactSlot, element }

  const typeSlots = slots.filter(slot => slot.type === type)
  if (typeSlots.length === 1) return { slot: typeSlots[0], element }

  const fallbackId = getImportedNativeElementSlotId(element, type, 0)
  const fallbackSlot = slots.find(slot => slot.type === type && slot.id === fallbackId)
  return fallbackSlot ? { slot: fallbackSlot, element } : null
}

const getImportedNativeElementLabel = (element: Element, type: ImportedNativeElementType, id: string) => {
  const explicitLabel = getImportedNativeElementAttr(element, [
    'data-rstk-label',
    'data-ristak-label',
    'data-ristack-label',
    'aria-label',
    'title'
  ])
  if (explicitLabel) return explicitLabel
  const text = String(element.textContent || '').replace(/\s+/g, ' ').trim()
  if (text) return text.slice(0, 80)
  return `${importedNativeElementTypeLabels[type]} ${id}`
}

const importedHtmlVideoRuleAttributeNames = [
  'data-rstk-video-rules',
  'data-ristak-video-rules',
  'data-ristack-video-rules'
]

const importedHtmlVideoPlayerSettingsAttributeNames = [
  'data-rstk-video-settings',
  'data-ristak-video-settings',
  'data-ristack-video-settings'
]

const parseImportedNativeVideoPlayerManifest = (
  element: Element,
  type: ImportedNativeElementType,
  explicitSlotId: string
) => {
  if (type !== 'video') return { present: false, settings: {} as Record<string, unknown>, error: '' }
  const attributeName = importedHtmlVideoPlayerSettingsAttributeNames.find(name => element.hasAttribute(name))
  if (!attributeName) return { present: false, settings: {} as Record<string, unknown>, error: '' }
  if (!explicitSlotId) {
    return {
      present: true,
      settings: {} as Record<string, unknown>,
      error: 'El video con data-rstk-video-settings necesita un data-rstk-native-id estable.'
    }
  }
  const manifest = normalizeImportedHtmlVideoPlayerManifest(element.getAttribute(attributeName) || '')
  return {
    present: true,
    settings: manifest.valid ? manifest.settings : {},
    error: manifest.error
  }
}

const parseImportedNativeVideoRuleManifest = (
  element: Element,
  type: ImportedNativeElementType,
  explicitSlotId: string
) => {
  if (type !== 'video') return { present: false, rules: [] as VideoActionRule[], error: '' }
  const attributeName = importedHtmlVideoRuleAttributeNames.find(name => element.hasAttribute(name))
  if (!attributeName) return { present: false, rules: [] as VideoActionRule[], error: '' }
  if (!explicitSlotId) {
    return {
      present: true,
      rules: [] as VideoActionRule[],
      error: 'El video con data-rstk-video-rules necesita un data-rstk-native-id estable.'
    }
  }

  try {
    const parsed = JSON.parse(element.getAttribute(attributeName) || '')
    if (!Array.isArray(parsed) || parsed.length > 100) {
      return { present: true, rules: [] as VideoActionRule[], error: 'data-rstk-video-rules debe contener una lista JSON de máximo 100 reglas.' }
    }
    const seenIds = new Set<string>()
    const rules: VideoActionRule[] = []
    for (let index = 0; index < parsed.length; index += 1) {
      const source = parsed[index]
      if (!source || typeof source !== 'object' || Array.isArray(source)) {
        return { present: true, rules: [] as VideoActionRule[], error: 'Cada regla de video debe ser un objeto JSON.' }
      }
      const id = String((source as Record<string, unknown>).id || '').trim()
      if (!id || id.length > 160 || seenIds.has(id)) {
        return { present: true, rules: [] as VideoActionRule[], error: 'Cada regla de video necesita un id estable, único y de máximo 160 caracteres.' }
      }
      seenIds.add(id)
      const deleted = (source as Record<string, unknown>).deleted
      if (deleted === true || deleted === 1 || deleted === 'true') continue
      const normalized = normalizeVideoActionRule({ ...(source as Record<string, unknown>), id }, index)
      if (!normalized || (videoActionTargetKinds.has(normalized.action) && !normalized.targetBlockId)) {
        return { present: true, rules: [] as VideoActionRule[], error: `La regla de video ${id} está incompleta o no tiene un target válido.` }
      }
      rules.push(normalized)
    }
    return { present: true, rules, error: '' }
  } catch {
    return { present: true, rules: [] as VideoActionRule[], error: 'data-rstk-video-rules no contiene JSON válido.' }
  }
}

const importedSocialProfileHookSelectors = {
  avatar: '[data-rstk-social-avatar],[data-ristak-social-avatar],[data-ristack-social-avatar]',
  name: '[data-rstk-social-name],[data-ristak-social-name],[data-ristack-social-name]',
  followers: '[data-rstk-social-followers],[data-ristak-social-followers],[data-ristack-social-followers]',
  verified: '[data-rstk-social-verified],[data-ristak-social-verified],[data-ristack-social-verified]'
}

const getImportedCustomSocialProfileHooksError = (
  element: Element,
  type: ImportedNativeElementType,
  renderMode: ImportedNativeElementRenderMode
) => {
  if (type !== 'social_profile' || renderMode !== 'custom') return ''
  const missing = Object.entries(importedSocialProfileHookSelectors)
    .filter(([key, selector]) => {
      const match = element.matches(selector) ? element : element.querySelector(selector)
      return !match || (key === 'avatar' && match.tagName.toLowerCase() !== 'img')
    })
    .map(([key]) => key === 'avatar' ? 'foto' : key === 'name' ? 'nombre' : key === 'followers' ? 'seguidores' : 'verificado')
  return missing.length
    ? `El perfil social con diseño propio necesita hooks para ${missing.join(', ')}.`
    : ''
}

const detectImportedNativeElementSlots = (html = ''): ImportedNativeElementSlot[] => {
  if (!html || typeof DOMParser === 'undefined') return []
  try {
    const doc = new DOMParser().parseFromString(html, 'text/html')
    const seen = new Set<string>()
    return Array.from(doc.querySelectorAll(importedNativeElementSelector))
      .map((element, index): ImportedNativeElementSlot | null => {
        const type = getImportedNativeElementTypeFromElement(element)
        if (!type) return null
        const id = getImportedNativeElementSlotId(element, type, index)
        const explicitSlotId = getImportedNativeElementExplicitSlotId(element)
        const videoPlayerManifest = parseImportedNativeVideoPlayerManifest(element, type, explicitSlotId)
        const videoRuleManifest = parseImportedNativeVideoRuleManifest(element, type, explicitSlotId)
        const renderMode = getImportedNativeElementRenderMode(element, type)
        const socialProfileHooksError = getImportedCustomSocialProfileHooksError(element, type, renderMode)
        const key = `${type}:${id}`
        if (seen.has(key)) return null
        seen.add(key)
        return {
          key,
          id,
          type,
          renderMode,
          label: getImportedNativeElementLabel(element, type, id),
          tagName: element.tagName.toLowerCase(),
          ...(videoPlayerManifest.present ? {
            videoPlayerSettingsAttributePresent: true,
            declaredVideoPlayerSettings: videoPlayerManifest.settings,
            videoPlayerSettingsError: videoPlayerManifest.error
          } : {}),
          ...(videoRuleManifest.present ? {
            videoRulesAttributePresent: true,
            declaredVideoActions: videoRuleManifest.rules,
            videoRulesError: videoRuleManifest.error
          } : {}),
          ...(socialProfileHooksError ? { socialProfileHooksError } : {})
        }
      })
      .filter(Boolean) as ImportedNativeElementSlot[]
  } catch {
    return []
  }
}

const detectImportedNativeElementDuplicateIds = (html = '') => {
  if (!html || typeof DOMParser === 'undefined') return []
  try {
    const doc = new DOMParser().parseFromString(html, 'text/html')
    const seen = new Set<string>()
    const duplicates = new Set<string>()
    Array.from(doc.querySelectorAll(importedNativeElementSelector)).forEach((element, index) => {
      const type = getImportedNativeElementTypeFromElement(element)
      if (!type) return
      const id = getImportedNativeElementSlotId(element, type, index)
      const key = `${type}:${id}`
      if (seen.has(key)) duplicates.add(`${importedNativeElementTypeLabels[type]} · ${id}`)
      seen.add(key)
    })
    return [...duplicates]
  } catch {
    return []
  }
}

const getImportedNativeElementBlockSettings = (slot: ImportedNativeElementSlot, pageId = '') => ({
  importedHtmlNativeElement: true,
  importedHtmlNativeSlotId: slot.id,
  importedHtmlNativeType: slot.type,
  importedHtmlNativeRenderMode: slot.renderMode,
  importedHtmlNativeLabel: slot.label,
  ...(pageId ? { pageId } : {})
})

const isImportedNativeElementBlock = (block: SiteBlock, slot: ImportedNativeElementSlot) => {
  const settings = block.settings || {}
  const slotPageId = String(slot.pageId || '').trim()
  const blockPageId = getSettingString(settings, 'pageId') || getSettingString(settings, 'page_id')
  return Boolean(settings.importedHtmlNativeElement) &&
    getSettingString(settings, 'importedHtmlNativeSlotId') === slot.id &&
    getSettingString(settings, 'importedHtmlNativeType') === slot.type &&
    block.blockType === importedNativeElementBlockTypes[slot.type] &&
    (!slotPageId || !blockPageId || blockPageId === slotPageId)
}

const findImportedNativeElementBlock = (blocks: SiteBlock[] = [], slot: ImportedNativeElementSlot) =>
  blocks.find(block => isImportedNativeElementBlock(block, slot)) || null

const findImportedNativeResponsiveFallbackBlock = (blocks: SiteBlock[] = [], slot: ImportedNativeElementSlot) => {
  if (slot.type !== 'video') return null
  const slotPageId = String(slot.pageId || '').trim()
  const candidates = blocks.filter(block => {
    const settings = block.settings || {}
    const blockPageId = getSettingString(settings, 'pageId') || getSettingString(settings, 'page_id')
    return block.blockType === 'video' &&
      Boolean(settings.importedHtmlNativeElement) &&
      getSettingString(settings, 'importedHtmlNativeType') === 'video' &&
      areImportedNativeResponsiveVariants(slot.id, getSettingString(settings, 'importedHtmlNativeSlotId')) &&
      (!slotPageId || !blockPageId || blockPageId === slotPageId)
  })
  return candidates.length === 1 ? candidates[0] : null
}

const getVisibleImportedNativeElementSlotKeys = (
  frame: HTMLIFrameElement,
  slots: ImportedNativeElementSlot[] = []
) => {
  const doc = frame.contentDocument
  const view = doc?.defaultView
  if (!doc || !view) return []
  const mountedElements = Array.from(doc.querySelectorAll<HTMLElement>('[data-rstk-native-slot-id][data-rstk-native-type]'))
  const isVisible = (element: HTMLElement) => {
    let current: HTMLElement | null = element
    while (current && current !== doc.documentElement) {
      const style = view.getComputedStyle(current)
      if (style.display === 'none' || style.visibility === 'hidden' || style.visibility === 'collapse') return false
      current = current.parentElement
    }
    return element.getClientRects().length > 0
  }
  return slots
    .filter(slot => mountedElements.some(element => (
      element.dataset.rstkNativeSlotId === slot.id &&
      element.dataset.rstkNativeType === slot.type &&
      isVisible(element)
    )))
    .map(slot => slot.key)
}

const IMPORTED_POPUP_PATTERN = /(<dialog\b|role=["']dialog["']|aria-modal=["']true["']|(?:id|class|data-[\w-]+)=["'][^"']*(?:popup|pop-up|modal|dialog|lightbox|overlay|exit-intent|newsletter)[^"']*["'])/i
const importedHtmlHasPopup = (importData?: ImportedSiteImport | null) => {
  const html = `${importData?.htmlSanitized || ''}\n${importData?.htmlOriginal || ''}`
  return IMPORTED_POPUP_PATTERN.test(html)
}
