const getBlockVisibility = (block?: SiteBlock | null) => (
  resolveBlockVisibility(block || {}) as { desktop: boolean; mobile: boolean }
)

const isBlockHidden = (block?: SiteBlock | null) => {
  const visibility = getBlockVisibility(block)
  return !visibility.desktop && !visibility.mobile
}

const getBlockVisibilityPatch = (
  nextVisibility: { desktop: boolean; mobile: boolean }
) => ({
  visibleOnDesktop: nextVisibility.desktop,
  visibleOnMobile: nextVisibility.mobile,
  hidden: !nextVisibility.desktop && !nextVisibility.mobile
})

const isLanding = (site?: PublicSite | null) => site?.siteType === 'landing_page'
const isStandardForm = (site?: PublicSite | null) => site?.siteType === 'standard_form'
const isInteractiveForm = (site?: PublicSite | null) => site?.siteType === 'interactive_form'
const isFormSite = (site?: PublicSite | null) => site?.siteType === 'standard_form' || site?.siteType === 'interactive_form'
const hasEditablePages = (site?: PublicSite | null) => isLanding(site) || isInteractiveForm(site) || isStandardForm(site)
const canManagePages = (site?: PublicSite | null) => hasEditablePages(site)
const isFormFinalPageId = (pageId?: string) => Boolean(pageId && FORM_FINAL_PAGE_IDS.has(pageId))
const isFormFinalPage = (page?: SitePage | null) => isFormFinalPageId(page?.id)
const getManualRedirectPages = (pages: SitePage[], activePageId?: string) => (
  pages.filter(page => page.id !== activePageId && !isFormFinalPage(page))
)

const formatDate = (value?: string | null) => {
  return formatBusinessDateTime(value, {
    fallback: value || 'Sin fecha',
    intlOptions: {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    }
  })
}

const formatSubmissionValue = (value: unknown) => {
  if (Array.isArray(value)) return value.map(item => String(item ?? '').trim()).filter(Boolean).join(', ')
  if (typeof value === 'object' && value !== null) return JSON.stringify(value)
  return String(value ?? '').trim()
}

const getSubmissionRulesSummary = (submission: SiteSubmission) => {
  const rules = submission.meta?.rules && typeof submission.meta.rules === 'object'
    ? submission.meta.rules as Record<string, unknown>
    : {}
  const tags = Array.isArray(rules.tags) ? rules.tags.map(item => String(item)).filter(Boolean).join(', ') : ''
  const categories = Array.isArray(rules.categories) ? rules.categories.map(item => String(item)).filter(Boolean).join(', ') : ''
  return [tags, categories].filter(Boolean).join(' / ') || 'Sin reglas'
}

const getFormResponseLabelMap = (site?: PublicSite | null) => {
  const labelMap = new Map<string, string>()
  const blocks = [...(site?.blocks || [])].sort((a, b) => a.sortOrder - b.sortOrder)

  blocks.forEach((block) => {
    if (!fieldBlockTypes.has(block.blockType)) return
    const label = String(block.label || block.content || block.placeholder || blockLabels[block.blockType] || 'Campo').trim()
    labelMap.set(block.id, label)
  })

  return labelMap
}

const getSubmissionAnswerPreview = (submission: SiteSubmission, site?: PublicSite | null, maxItems = 3) => {
  const labelMap = getFormResponseLabelMap(site)
  const source = Object.keys(submission.responses || {}).length
    ? submission.responses
    : submission.rawFields || {}
  const items = Object.entries(source)
    .map(([key, value]) => ({
      label: labelMap.get(key) || key,
      value: formatSubmissionValue(value)
    }))
    .filter(item => item.value)

  if (!items.length && submission.mappedFields && typeof submission.mappedFields === 'object') {
    return Object.entries(submission.mappedFields)
      .map(([key, value]) => ({ label: key, value: formatSubmissionValue(value) }))
      .filter(item => item.value)
      .slice(0, maxItems)
  }

  return items.slice(0, maxItems)
}

const formatSitesCompactNumber = (value?: number | null) => {
  const parsed = Number(value || 0)
  if (!Number.isFinite(parsed)) return '0'
  return new Intl.NumberFormat('es-MX', { notation: parsed >= 10000 ? 'compact' : 'standard', maximumFractionDigits: 1 }).format(parsed)
}

const formatSitesDecimal = (value?: number | null) => {
  const parsed = Number(value || 0)
  if (!Number.isFinite(parsed)) return '0'
  return new Intl.NumberFormat('es-MX', { maximumFractionDigits: 1 }).format(parsed)
}

const formatSitesPercent = (value?: number | null) => {
  const parsed = Number(value || 0)
  if (!Number.isFinite(parsed)) return '0%'
  return `${new Intl.NumberFormat('es-MX', { maximumFractionDigits: parsed >= 10 ? 0 : 1 }).format(parsed)}%`
}

const getSitesCompletionTone = (value?: number | null): BadgeVariant => {
  const rate = Number(value || 0)
  if (!Number.isFinite(rate)) return 'neutral'
  if (rate >= 80) return 'success'
  if (rate >= 50) return 'warning'
  return 'error'
}

const formatSitesSeconds = (value?: number | null) => {
  const total = Math.max(0, Math.round(Number(value || 0)))
  if (!Number.isFinite(total) || total <= 0) return '0s'
  if (total < 60) return `${total}s`
  const minutes = Math.floor(total / 60)
  const seconds = total % 60
  if (minutes < 60) return seconds ? `${minutes}m ${seconds}s` : `${minutes}m`
  const hours = Math.floor(minutes / 60)
  const restMinutes = minutes % 60
  return restMinutes ? `${hours}h ${restMinutes}m` : `${hours}h`
}

const getSitesAnalyticsRange = (startValue: Date, endValue: Date) => {
  const start = startValue instanceof Date ? startValue : new Date(startValue)
  const end = endValue instanceof Date ? endValue : new Date(endValue)
  const startDay = new Date(start.getFullYear(), start.getMonth(), start.getDate())
  const endDay = new Date(end.getFullYear(), end.getMonth(), end.getDate())
  const days = Math.max(1, Math.round((endDay.getTime() - startDay.getTime()) / 86400000) + 1)

  return {
    dateFrom: formatDateToISO(start),
    dateTo: formatDateToISO(end),
    hourly: days <= 7
  }
}

const getMediaMetadataRecord = (asset?: MediaAsset | null) => {
  const metadata = asset?.metadata
  return metadata && typeof metadata === 'object' ? metadata as Record<string, unknown> : {}
}

const getMediaAnalyticsSourceSiteRecord = (asset?: MediaAsset | null) => {
  const sourceSite = getMediaMetadataRecord(asset).analyticsSourceSite
  return sourceSite && typeof sourceSite === 'object'
    ? sourceSite as Record<string, unknown>
    : {}
}

const getMediaSourceSiteName = (asset?: MediaAsset | null) => {
  const name = getMediaAnalyticsSourceSiteRecord(asset).name
  return typeof name === 'string' ? name.trim() : ''
}

const getMediaStreamRecord = (asset?: MediaAsset | null) => {
  const stream = getMediaMetadataRecord(asset).stream
  return stream && typeof stream === 'object' ? stream as Record<string, unknown> : {}
}

const getMediaStreamSourceRecord = (asset?: MediaAsset | null) => {
  const source = getMediaStreamRecord(asset).source
  return source && typeof source === 'object' ? source as Record<string, unknown> : {}
}

const getMediaStreamVideoRecord = (asset?: MediaAsset | null) => {
  const video = getMediaStreamRecord(asset).video
  return video && typeof video === 'object' ? video as Record<string, unknown> : {}
}

const getMediaStreamVideoId = (asset?: MediaAsset | null) => {
  const videoId = getMediaStreamRecord(asset).videoId
  return typeof videoId === 'string' ? videoId.trim() : ''
}

const getMediaSourceSiteId = (asset?: MediaAsset | null) => {
  const source = getMediaStreamSourceRecord(asset)
  const sourceEntityId = typeof source.moduleEntityId === 'string' ? source.moduleEntityId.trim() : ''
  const analyticsSourceId = getMediaAnalyticsSourceSiteRecord(asset).id
  const normalizedAnalyticsSourceId = typeof analyticsSourceId === 'string' ? analyticsSourceId.trim() : ''
  return sourceEntityId || asset?.moduleEntityId || normalizedAnalyticsSourceId
}

const readSitesNumber = (value: unknown) => {
  const parsed = Number(value)
  return Number.isFinite(parsed) ? parsed : 0
}

const getSiteAnalyticsStats = (site: PublicSite) => {
  const views = readSitesNumber(site.trackingStats?.views)
  const visitors = readSitesNumber(site.trackingStats?.visitors)
  const sessions = readSitesNumber(site.trackingStats?.sessions)
  const conversions = readSitesNumber(site.trackingStats?.conversions) || readSitesNumber(site.submissionsCount)
  const conversionRate = readSitesNumber(site.trackingStats?.conversionRate)

  return {
    views,
    visitors,
    sessions,
    conversions,
    conversionRate: conversionRate || (visitors > 0 ? Number(((conversions / visitors) * 100).toFixed(1)) : 0)
  }
}

const formatSitesChartLabel = (value = '', compact = false) => {
  const calendarDate = getDateOnlyFromCalendarLikeString(value)
  return formatBusinessDateTime(value, {
    fallback: value,
    intlOptions: compact || calendarDate
      ? { day: '2-digit', month: 'short' }
      : { day: '2-digit', month: 'short', hour: '2-digit' }
  })
}

const buildSitesChartPoints = (points: StreamChartPoint[] = [], mode: 'count' | 'seconds' = 'count') => (
  points.map(point => ({
    ...point,
    label: formatSitesChartLabel(point.label || point.periodKey || '', mode === 'count'),
    value: mode === 'seconds' ? Math.round((Number(point.value || 0) / 60) * 10) / 10 : Number(point.value || 0)
  }))
)

const hasSitesChartValue = (points: StreamChartPoint[] = []) => (
  points.some(point => Number(point.value || 0) > 0)
)

const selectSitesChartSource = (
  primary: StreamChartPoint[] = [],
  fallback: StreamChartPoint[] = [],
  preferPrimary = false
) => {
  if (preferPrimary && primary.length) return primary
  if (hasSitesChartValue(primary)) return primary
  if (hasSitesChartValue(fallback)) return fallback
  return primary.length ? primary : fallback
}

const clampSitesPercent = (value: unknown) => {
  const number = Number(value)
  if (!Number.isFinite(number)) return 0
  return Math.min(100, Math.max(0, number))
}

const formatSitesTimecode = (value: unknown) => {
  const totalSeconds = Math.max(0, Math.floor(readSitesNumber(value)))
  const minutes = Math.floor(totalSeconds / 60)
  const seconds = totalSeconds % 60
  return `${minutes}:${String(seconds).padStart(2, '0')}`
}

const buildSitesRetentionSegments = (
  firstPartySegments: FirstPartyVideoRetentionSegment[] = [],
  bunnyHeatmap: MediaStreamAnalytics['heatmap'] = []
): FirstPartyVideoRetentionSegment[] => {
  if (firstPartySegments.length) return firstPartySegments
  return bunnyHeatmap.map((point, index) => ({
    segment: index,
    startPercent: index,
    endPercent: index + 1,
    startSeconds: 0,
    endSeconds: 0,
    label: point.label || `${point.segment}`,
    retainedSessions: 0,
    skippedSessions: 0,
    replayedSessions: 0,
    retentionPercent: clampSitesPercent(point.intensity),
    replayRatePercent: 0,
    intensity: clampSitesPercent(point.intensity)
  }))
}

const buildSitesRetentionCurvePoints = (segments: FirstPartyVideoRetentionSegment[]) => {
  if (!segments.length) return ''
  const lastIndex = Math.max(1, segments.length - 1)
  return segments.map((segment, index) => {
    const x = (index / lastIndex) * 100
    const y = 100 - clampSitesPercent(segment.retentionPercent)
    return `${x.toFixed(2)},${y.toFixed(2)}`
  }).join(' ')
}

const buildSitesRetentionAreaPath = (points: string) => (
  points ? `M 0 100 L ${points.split(' ').join(' L ')} L 100 100 Z` : ''
)

const getSitesViewerName = (viewer: FirstPartyVideoViewer) => (
  viewer.contactName ||
  viewer.contactEmail ||
  viewer.contactPhone ||
  (viewer.visitorId ? `Visitante ${String(viewer.visitorId).slice(-6)}` : 'Visitante anónimo')
)

const getSitesViewerMeta = (viewer: FirstPartyVideoViewer) => {
  const page = viewer.publicPageTitle || viewer.pageUrl
  const block = viewer.blockLabel
  return [block, page].filter(Boolean).join(' · ') || (viewer.contactId ? 'Contacto identificado' : 'Sin contacto')
}

const buildSitesViewerHeatmapSegments = (viewer: FirstPartyVideoViewer, segmentCount = 18) => {
  const progress = clampSitesPercent(viewer.maxProgressPercent)
  const replayed = Number(viewer.playCount || 0) > 1
  const completed = Boolean(viewer.completed) || progress >= 99

  return Array.from({ length: segmentCount }, (_, index) => {
    const start = (index / segmentCount) * 100
    const end = ((index + 1) / segmentCount) * 100
    const watched = completed || start < progress
    const hot = replayed && watched && end <= progress
    return {
      index,
      label: `${Math.round(start)}-${Math.round(end)}%`,
      state: !watched ? 'skipped' : hot ? 'replayed' : 'played'
    }
  })
}

const getSiteTypeFilterMatch = (site: PublicSite, selectedType: SitesAnalyticsSiteType) => {
  if (selectedType === 'videos') return true
  if (selectedType === 'sites') return site.siteType === 'landing_page'
  return isFormSite(site)
}

const shortenSitesText = (value: string, maxLength = 48) => {
  const normalized = value.trim()
  if (normalized.length <= maxLength) return normalized
  const tailLength = Math.max(8, Math.round(maxLength * 0.28))
  const headLength = Math.max(12, maxLength - tailLength - 3)
  return `${normalized.slice(0, headLength).trim()}...${normalized.slice(-tailLength).trim()}`
}

const getMediaAssetDisplayName = (asset: MediaAsset) => (
  (asset.originalFilename || asset.storedFilename || 'Video')
    .replace(/\.[a-z0-9]{2,5}$/i, '')
    .trim() || 'Video'
)

const getSiteAnalyticsVideoLabel = (asset: MediaAsset, sitesById: Map<string, PublicSite>) => {
  const siteName = sitesById.get(getMediaSourceSiteId(asset))?.name || getMediaSourceSiteName(asset)
  const videoName = shortenSitesText(getMediaAssetDisplayName(asset), siteName ? 34 : 54)
  return [videoName, siteName ? shortenSitesText(siteName, 24) : ''].filter(Boolean).join(' · ')
}

const getSiteAnalyticsVideoMetric = (asset: MediaAsset, key: string) => (
  readSitesNumber(getMediaStreamVideoRecord(asset)[key])
)

type SitesVideoAggregateRow = {
  asset: MediaAsset
  key: string
  label: string
  sourceSiteId: string
  sourceLabel: string
  streamVideoId: string
  playbackSessions: number
  playedSessions: number
  totalViewers: number
  completions: number
  views: number
  watchTime: number
  averageWatchTime: number
  engagementScore: number
}

const buildSitesVideoAggregateRows = (
  videos: MediaAsset[],
  sitesById: Map<string, PublicSite>,
  aggregateByAssetId: SitesAnalyticsSummary['videos']['byAssetId'] | null = null
): SitesVideoAggregateRow[] => (
  videos.map((asset) => {
    const sourceSiteId = getMediaSourceSiteId(asset)
    const sourceLabel = sitesById.get(sourceSiteId)?.name || getMediaSourceSiteName(asset) || 'Sin origen'
    const aggregate = aggregateByAssetId?.[asset.id] || null
    const views = aggregate ? readSitesNumber(aggregate.plays) : getSiteAnalyticsVideoMetric(asset, 'views')
    const watchTime = aggregate ? readSitesNumber(aggregate.watchedSeconds) : getSiteAnalyticsVideoMetric(asset, 'totalWatchTime')
    return {
      asset,
      key: asset.id,
      label: getSiteAnalyticsVideoLabel(asset, sitesById),
      sourceSiteId,
      sourceLabel,
      streamVideoId: getMediaStreamVideoId(asset),
      playbackSessions: aggregate ? readSitesNumber(aggregate.playbackSessions) : 0,
      playedSessions: aggregate ? readSitesNumber(aggregate.playedSessions) : views,
      totalViewers: aggregate ? readSitesNumber(aggregate.totalViewers) : 0,
      completions: aggregate ? readSitesNumber(aggregate.completions) : 0,
      views,
      watchTime,
      averageWatchTime: aggregate
        ? readSitesNumber(aggregate.averageWatchSeconds)
        : getSiteAnalyticsVideoMetric(asset, 'averageWatchTime') || (views > 0 ? watchTime / views : 0),
      engagementScore: aggregate
        ? readSitesNumber(aggregate.avgProgressPercent)
        : getSiteAnalyticsVideoMetric(asset, 'engagementScore')
    }
  })
)

const slugifyName = (value: string) => value
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_+|_+$/g, '') || 'field'

const getStatusLabel = (site: PublicSite, domainConfig: SitesDomainConfig) => {
  if (site.status !== 'published') return site.status === 'draft' ? 'Borrador' : 'Archivado'
  if (!domainConfig.domain) return 'Sin dominio'
  return domainConfig.renderDomainVerified ? 'Publicado' : 'Dominio pendiente'
}

// Fecha de edición relativa, compacta (estilo "hace 2 días" del ZIP)
const formatSiteEdited = (value?: string | null): string | null => {
  if (!value) return null
  const then = parseSortableDateValue(value)
  if (!Number.isFinite(then)) return null
  const days = Math.floor((Date.now() - then) / 86400000)
  if (days <= 0) return 'hoy'
  if (days === 1) return 'ayer'
  if (days < 7) return `hace ${days} días`
  if (days < 30) return `hace ${Math.floor(days / 7)} sem`
  if (days < 365) return `hace ${Math.floor(days / 30)} mes`
  return `hace ${Math.floor(days / 365)} año`
}

const getStatusVariant = (site: PublicSite, domainConfig: SitesDomainConfig): BadgeVariant => {
  if (site.status !== 'published') return 'neutral'
  if (!domainConfig.domain || !domainConfig.renderDomainVerified) return 'warning'
  return 'success'
}

const isPublicSiteLive = (site: PublicSite, domainConfig: SitesDomainConfig) =>
  site.status === 'published' && Boolean(domainConfig.domain && domainConfig.renderDomainVerified)

const normalizeRouteInput = (value: string) => value
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/^\/+/, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')

const getRoutePath = (site?: PublicSite | null) => `/${normalizeRouteInput(site?.slug || '')}`

const appendNoTrackToUrl = (url: string) => {
  if (!url) return url
  try {
    const parsed = new URL(url, window.location.origin)
    parsed.searchParams.set('no_track', '1')
    return parsed.toString()
  } catch {
    const [base, hash = ''] = url.split('#')
    const separator = base.includes('?') ? '&' : '?'
    return `${base}${separator}no_track=1${hash ? `#${hash}` : ''}`
  }
}

const shouldOpenSiteWithoutTracking = (site: PublicSite) => site.antiTrackingEnabled !== false

const buildLivePublicUrl = (site: PublicSite, domainConfig: SitesDomainConfig, options: { noTrack?: boolean } = {}) => {
  const url = domainConfig.domain ? `https://${domainConfig.domain}${getRoutePath(site)}` : ''
  return options.noTrack ? appendNoTrackToUrl(url) : url
}

const getPublicRouteLabel = (site: PublicSite, domainConfig: SitesDomainConfig) =>
  domainConfig.domain ? `${domainConfig.domain}${getRoutePath(site)}` : getRoutePath(site)

const getDefaultPublicRouteSiteId = (domainConfig: SitesDomainConfig) =>
  domainConfig.defaultRoute?.siteId || ''

const isDefaultPublicRoute = (site: PublicSite, domainConfig: SitesDomainConfig) =>
  Boolean(site.id && site.id === getDefaultPublicRouteSiteId(domainConfig))

const getDefaultPublicRoutePageId = (site: PublicSite | null | undefined, domainConfig: SitesDomainConfig) =>
  site?.id && site.id === getDefaultPublicRouteSiteId(domainConfig)
    ? domainConfig.defaultRoute?.pageId || ''
    : ''

const isDefaultPublicRoutePage = (site: PublicSite | null | undefined, domainConfig: SitesDomainConfig, pageId: string) =>
  Boolean(pageId && getDefaultPublicRoutePageId(site, domainConfig) === pageId)

const getPublicDomainPreview = (domainConfig: SitesDomainConfig) => {
  const domain = domainConfig.domain.trim().replace(/^https?:\/\//i, '').replace(/\/+$/, '')
  return domain || 'www.ejemplo-de-tu-dominio.com'
}

const getConfiguredPublicDomain = (domainConfig: SitesDomainConfig) =>
  domainConfig.domain.trim().replace(/^https?:\/\//i, '').replace(/\/+$/, '')

const getPublicDomainRootUrl = (domainConfig: SitesDomainConfig) => {
  const domain = getConfiguredPublicDomain(domainConfig)
  return domain ? `https://${domain}/` : ''
}

const DOMAIN_ROOT_PAGE_VALUE_SEPARATOR = '::'

const encodeDomainRootPageValue = (siteId: string, pageId: string) =>
  `${siteId}${DOMAIN_ROOT_PAGE_VALUE_SEPARATOR}${pageId}`

const decodeDomainRootPageValue = (value: string) => {
  const [siteId = '', pageId = ''] = value.split(DOMAIN_ROOT_PAGE_VALUE_SEPARATOR)
  return { siteId, pageId }
}

const getDefaultSiteNamePrefix = (siteType: SiteType) =>
  siteType === 'landing_page' ? 'Sitio' : 'Formulario'

const getDefaultRoutePrefix = (siteType: SiteType) =>
  normalizeRouteInput(getDefaultSiteNamePrefix(siteType))

const getRouteEditorValue = (site?: PublicSite | null) => normalizeRouteInput(site?.slug || '')

const normalizeRouteEditorInput = (value: string, domainConfig: SitesDomainConfig) => {
  const raw = value.trim()
  if (/^https?:\/\//i.test(raw)) {
    try {
      return normalizeRouteInput(new URL(raw).pathname)
    } catch {
      return normalizeRouteInput(raw)
    }
  }

  const withoutProtocol = raw.replace(/^https?:\/\//i, '')
  const domain = getPublicDomainPreview(domainConfig).replace(/^https?:\/\//i, '').replace(/\/+$/, '')
  const withoutDomain = withoutProtocol.toLowerCase().startsWith(`${domain.toLowerCase()}/`)
    ? withoutProtocol.slice(domain.length)
    : raw

  return normalizeRouteInput(withoutDomain)
}

const getNextSiteIdentity = (siteType: SiteType, existingSites: PublicSite[]) => {
  const namePrefix = getDefaultSiteNamePrefix(siteType)
  const routePrefix = getDefaultRoutePrefix(siteType)
  const used = new Set(existingSites.map(site => normalizeRouteInput(site.slug)))
  let index = 1
  let suffix = String(index).padStart(2, '0')
  let slug = `${routePrefix}-${suffix}`

  while (used.has(slug)) {
    index += 1
    suffix = String(index).padStart(2, '0')
    slug = `${routePrefix}-${suffix}`
  }

  return {
    name: `${namePrefix} ${suffix}`,
    slug
  }
}

const legacyPublicTitleDefaults = new Set([
  'nuevo sitio embudo',
  'nuevo sitio de embudo',
  'nuevo formulario',
  'nuevo formulario interactivo'
])

const isLegacyPublicTitleDefault = (site?: PublicSite | null) =>
  Boolean(site?.title && legacyPublicTitleDefaults.has(site.title.trim().toLowerCase()))

const getPublicTitleEditorValue = (site?: PublicSite | null) =>
  isLegacyPublicTitleDefault(site) ? '' : site?.title || ''

const getPublicTitleForSave = (site: PublicSite) =>
  isLegacyPublicTitleDefault(site) ? '' : site.title

const formatEditorSavedAt = (savedAt: number, now: number) => {
  const elapsedSeconds = Math.max(0, Math.floor((now - savedAt) / 1000))
  if (elapsedSeconds < 10) return 'Guardado hace unos segundos'
  if (elapsedSeconds < 60) return `Guardado hace ${elapsedSeconds} segundos`

  const elapsedMinutes = Math.floor(elapsedSeconds / 60)
  if (elapsedMinutes <= 1) return 'Guardado hace 1 minuto'
  if (elapsedMinutes < 60) return `Guardado hace ${elapsedMinutes} minutos`

  return 'Guardado'
}

const templateMetaById = (id?: string) => siteTemplates.find(template => template.id === id)

const getTemplateThemeDefaults = (id: SiteTemplateId, siteType: SiteType): Partial<SiteTheme> => {
  const defaults = { ...(templateMetaById(id)?.defaultTheme || {}) }
  if (siteType !== 'landing_page') return defaults

  return {
    ...defaults,
    pageMaxWidth: defaults.pageMaxWidth ?? 1440,
    pagePadding: defaults.pagePadding ?? LANDING_DEFAULT_PAGE_PADDING
  }
}

