const normalizeFormChoiceStyle = (value: unknown): FormChoiceStyle => {
  const raw = String(value || '').trim()
  return formChoiceStyleOptions.some(option => option.value === raw) ? raw as FormChoiceStyle : 'native'
}

const normalizeFormSelectStyle = (value: unknown): FormSelectStyle => {
  const raw = String(value || '').trim()
  return formSelectStyleOptions.some(option => option.value === raw) ? raw as FormSelectStyle : 'classic'
}

const normalizeFormInputStyle = (value: unknown): FormInputStyle => {
  const raw = String(value || '').trim()
  return formInputStyleOptions.some(option => option.value === raw) ? raw as FormInputStyle : 'box'
}

// Estilo elegido SOLO para este campo (override del estilo global del formulario).
// Vacío = el campo hereda el estilo global del lienzo (comportamiento de siempre).
// Devuelve el sufijo de clases para el <section class="rstk-field">: el marcador
// rstk-fieldstyled (resetea los residuos del estilo global) + la variante concreta.
const getFieldOwnStyleClass = (block: SiteBlock): string => {
  const settings = block.settings || {}
  let variant = ''
  if (block.blockType === 'radio' || block.blockType === 'checkboxes') {
    const raw = getSettingString(settings, 'choiceStyle')
    if (raw) variant = `rstk-choice-${normalizeFormChoiceStyle(raw)}`
  } else if (block.blockType === 'dropdown') {
    const raw = getSettingString(settings, 'selectStyle')
    if (raw) variant = `rstk-select-${normalizeFormSelectStyle(raw)}`
  } else if (fieldBlockTypes.has(block.blockType)) {
    const raw = getSettingString(settings, 'inputStyle')
    if (raw) variant = `rstk-input-${normalizeFormInputStyle(raw)}`
  }
  return variant ? ` rstk-fieldstyled ${variant}` : ''
}

// Unificado con el publicado (content #7): mismo normalizador compartido, con
// fallback configurable (el bloque de perfil cae al template social del sitio).
const normalizeSocialPlatform = (value: unknown, fallback: SocialPlatform = 'facebook'): SocialPlatform =>
  normalizeSharedSocialPlatform(value, fallback) as SocialPlatform

const socialProfileOptionLabel = (profile: ConnectedSocialProfile) => {
  const platform = socialPlatformOptions.find(option => option.value === profile.platform)?.label || profile.platform
  const followers = profile.followersLabel ? ` - ${profile.followersLabel} seguidores` : ''
  const owner = profile.pageName && profile.pageName !== profile.name ? ` (${profile.pageName})` : ''
  return `${platform}: ${profile.name}${owner}${followers}`
}

const parseSocialFollowerCount = (value: unknown) => {
  if (typeof value === 'number' && Number.isFinite(value)) return value

  const raw = String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
  if (!raw) return 0

  const match = raw.match(/(\d+(?:[.,]\d+)?)/)
  if (!match) return 0

  const amount = Number(match[1].replace(',', '.'))
  if (!Number.isFinite(amount)) return 0

  if (/\b(k|mil|thousand)\b/.test(raw)) return amount * 1000
  if (/\b(m|mm|millon|millones|million|millions)\b/.test(raw)) return amount * 1000000
  return amount
}

const getConnectedSocialProfileFollowerCount = (profile: ConnectedSocialProfile) =>
  typeof profile.followers === 'number' && Number.isFinite(profile.followers)
    ? profile.followers
    : parseSocialFollowerCount(profile.followersLabel)

const isConfiguredConnectedSocialProfile = (profile: ConnectedSocialProfile) =>
  Boolean(profile.isConfiguredPage || profile.isConfiguredInstagram)

const sortConnectedSocialProfilesByPriority = (profiles: ConnectedSocialProfile[]) =>
  [...profiles].sort((left, right) => {
    const followersDelta = getConnectedSocialProfileFollowerCount(right) - getConnectedSocialProfileFollowerCount(left)
    if (followersDelta !== 0) return followersDelta

    const configuredDelta = Number(isConfiguredConnectedSocialProfile(right)) - Number(isConfiguredConnectedSocialProfile(left))
    if (configuredDelta !== 0) return configuredDelta

    return socialPlatformOptions.findIndex(option => option.value === left.platform) - socialPlatformOptions.findIndex(option => option.value === right.platform)
  })

const getBestConnectedSocialProfile = (profiles: ConnectedSocialProfile[]): ConnectedSocialProfile | null =>
  sortConnectedSocialProfilesByPriority(profiles)[0] || null

const connectedSocialProfileBlockPatch = (profile: ConnectedSocialProfile): Record<string, unknown> => ({
  platform: profile.platform,
  brandName: profile.name,
  brandSubtitle: profile.platform === 'instagram'
    ? 'Perfil de Instagram conectado'
    : profile.platform === 'facebook'
      ? 'Página de Facebook conectada'
      : profile.platform === 'tiktok'
        ? 'Perfil de TikTok conectado'
        : profile.platform === 'threads'
          ? 'Perfil de Threads conectado'
          : 'Perfil conectado',
  brandAvatar: profile.avatarUrl || '',
  followers: profile.followersLabel || '',
  brandVerified: true,
  socialAutoSync: true,
  socialSourceProfileId: profile.id,
  socialSourcePlatform: profile.platform,
  socialSourceId: profile.sourceId,
  socialSourcePageId: profile.pageId || '',
  socialSourceName: profile.name,
  socialSyncedAt: profile.updatedAt || new Date().toISOString()
})

const socialProfileAutoPresetForNewBlock = (
  blockType: SiteBlockType,
  initialSettings: Record<string, unknown>,
  profiles: ConnectedSocialProfile[]
): Record<string, unknown> => {
  if (blockType !== 'social_profile') return initialSettings
  if (initialSettings.socialAutoSync === false || getSettingString(initialSettings, 'socialSourceProfileId')) return initialSettings

  const bestProfile = getBestConnectedSocialProfile(profiles)
  if (!bestProfile) return {
    ...initialSettings,
    socialAutoSync: true
  }

  return {
    ...initialSettings,
    ...connectedSocialProfileBlockPatch(bestProfile)
  }
}

const socialProfileDefaultsForSite = (site?: PublicSite | null): Record<string, unknown> => {
  const theme = site?.theme || {}
  const templatePlatform = platformChromeFor(resolveTemplateId(site))
  const sourcePlatform = normalizeSocialPlatform(theme.socialSourcePlatform)
  const platform = templatePlatform || sourcePlatform || 'facebook'

  return {
    platform,
    brandName: theme.brandName || getPublicTitleEditorValue(site) || site?.name || 'Tu marca',
    brandSubtitle: theme.brandSubtitle || (platform === 'instagram' ? 'Publicación pagada' : 'Patrocinado'),
    brandAvatar: theme.brandAvatar || '',
    followers: theme.followers || '',
    socialProfileScale: getSettingNumber(theme as Record<string, unknown>, 'socialProfileScale', DEFAULT_SOCIAL_PROFILE_SCALE, SOCIAL_PROFILE_SCALE_MIN, SOCIAL_PROFILE_SCALE_MAX),
    brandVerified: theme.brandVerified === undefined ? true : theme.brandVerified !== false,
    socialAutoSync: theme.socialAutoSync,
    socialSourceProfileId: theme.socialSourceProfileId || '',
    socialSourcePlatform: theme.socialSourcePlatform || '',
    socialSourceId: theme.socialSourceId || '',
    socialSourcePageId: theme.socialSourcePageId || '',
    socialSourceName: theme.socialSourceName || '',
    socialSyncedAt: theme.socialSyncedAt || ''
  }
}

