// Nota de seguridad por defecto — DEBE coincidir con PAYMENT_SECURE_NOTE_DEFAULT en
// backend/src/services/sitesService.js para que el preview y el checkout vivo sean idénticos.
const PAYMENT_SECURE_NOTE_DEFAULT = 'Pago seguro. La tarjeta se captura en campos cifrados del proveedor.'

// Acción posterior al pago EXITOSO. Se guarda en block.settings.postPayment y el backend
// (resolvePaymentPostAction / runtime) la ejecuta SOLO cuando el proveedor confirma el pago.
type PaymentPostActionKind = 'success_message' | 'next_page' | 'specific_page' | 'redirect_url'

const paymentPostActionOptions: Array<{ value: PaymentPostActionKind; label: string }> = [
  { value: 'success_message', label: 'Mostrar mensaje de éxito' },
  { value: 'next_page', label: 'Ir a la siguiente página' },
  { value: 'specific_page', label: 'Ir a una página específica' },
  { value: 'redirect_url', label: 'Redirigir a una URL externa' }
]
const paymentPostActionValues = new Set<PaymentPostActionKind>(paymentPostActionOptions.map(option => option.value))

interface PaymentPostAction {
  action: PaymentPostActionKind
  message: string
  pageId: string
  url: string
}

const PAYMENT_POST_SUCCESS_MESSAGE_DEFAULT = 'Tu pago fue realizado correctamente. Gracias por tu compra.'

const normalizePaymentPostAction = (value: unknown): PaymentPostAction => {
  const source = (value && typeof value === 'object' ? value : {}) as Partial<PaymentPostAction>
  const action = paymentPostActionValues.has(source.action as PaymentPostActionKind)
    ? (source.action as PaymentPostActionKind)
    : 'success_message'
  return {
    action,
    message: typeof source.message === 'string' ? source.message : '',
    pageId: typeof source.pageId === 'string' ? source.pageId : '',
    url: typeof source.url === 'string' ? source.url : ''
  }
}

const getPaymentPostActionFromSettings = (settings: Record<string, unknown> = {}): PaymentPostAction =>
  normalizePaymentPostAction((settings as { postPayment?: unknown }).postPayment)

const getNextSitePageId = (pages: SitePage[] = [], activePageId = '') => {
  const index = pages.findIndex(page => page.id === activePageId)
  return index >= 0 ? pages[index + 1]?.id || '' : pages[1]?.id || ''
}

const hasNextSitePage = (pages: SitePage[] = [], activePageId = '') => (
  Boolean(getNextSitePageId(pages, activePageId))
)

const paymentPostActionHasDestination = (post: PaymentPostAction, pages: SitePage[] = [], activePageId = '') => {
  if (post.action === 'success_message') return true
  if (post.action === 'next_page') return Boolean(getNextSitePageId(pages, activePageId))
  if (post.action === 'specific_page') return Boolean(post.pageId && pages.some(page => page.id === post.pageId))
  if (post.action === 'redirect_url') return Boolean(safeAbsoluteUrl(post.url))
  return false
}

const defaultPaymentGateConfig = (currencyFallback = 'MXN'): CommonPaymentGateConfig => normalizePaymentGateConfig({
  enabled: true,
  mode: 'test',
  gateway: 'stripe',
  billingType: 'single',
  amount: 100,
  currency: currencyFallback,
  productName: 'Pago requerido',
  description: 'Completa el pago para continuar.',
  buttonText: 'Completar pago',
  pendingMessage: 'Completa el pago para continuar.',
  paidMessage: 'Pago confirmado. Continuamos.',
  subscription: {
    intervalType: 'monthly',
    intervalCount: 1
  }
}, currencyFallback)

const getPaymentGateFromSettings = (settings: Record<string, unknown> = {}, currencyFallback = 'MXN') => {
  const source = settings.paymentGate && typeof settings.paymentGate === 'object'
    ? settings.paymentGate as Partial<CommonPaymentGateConfig>
    : {}
  return normalizePaymentGateConfig(source, currencyFallback)
}

const getPaymentGatewayLabel = (gateway: CommonPaymentGateConfig['gateway']) => (
  gateway === 'mercadopago' ? 'Mercado Pago' : gateway === 'conekta' ? 'Conekta' : gateway === 'clip' ? 'CLIP' : gateway === 'rebill' ? 'Rebill' : 'Stripe'
)

const getPaymentBillingTypeLabel = (paymentGate: CommonPaymentGateConfig) =>
  paymentGate.billingType === 'subscription' ? 'Suscripción' : 'Pago único'

const getPaymentSubscriptionCadenceLabel = (paymentGate: CommonPaymentGateConfig) => {
  const count = Math.max(1, Math.trunc(Number(paymentGate.subscription?.intervalCount || 1)))
  const interval = paymentGate.subscription?.intervalType || 'monthly'
  if (count === 1) {
    if (interval === 'daily') return 'día'
    if (interval === 'weekly') return 'semana'
    if (interval === 'yearly') return 'año'
    return 'mes'
  }
  if (interval === 'daily') return `${count} días`
  if (interval === 'weekly') return `${count} semanas`
  if (interval === 'yearly') return `${count} años`
  return `${count} meses`
}

// Espejo de isPaymentGateEnabled del backend (publicPaymentGateService):
// habilitado + monto > 0 + pasarela conocida.
const PAYMENT_GATE_GATEWAYS = new Set<CommonPaymentGateConfig['gateway']>(['stripe', 'conekta', 'mercadopago', 'clip', 'rebill'])

const isPaymentGateConfigEnabled = (config: CommonPaymentGateConfig) =>
  Boolean(config.enabled && config.amount > 0 && PAYMENT_GATE_GATEWAYS.has(config.gateway))

// Paridad form-fields #9: el publicado muestra el área de acciones también en
// páginas que solo tienen bloques de pago habilitados (incluidos los anidados
// en formularios embebidos), igual que findEnabledPaymentBlockContext.
const canvasHasEnabledPaymentBlock = (blocks: SiteBlock[]): boolean => blocks.some(block => {
  if (block.blockType === 'payment' && isPaymentGateConfigEnabled(getPaymentGateFromSettings(block.settings || {}))) return true
  const embedded = block.settings?.embeddedBlocks
  return Array.isArray(embedded) && canvasHasEnabledPaymentBlock(embedded as SiteBlock[])
})

const formatPaymentAmount = (amount: number, currency: string) => {
  const safeCurrency = /^[A-Z]{3}$/.test(currency || '') ? currency : 'MXN'
  if (!Number.isFinite(amount) || amount <= 0) return 'Monto pendiente'
  try {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: safeCurrency
    }).format(amount)
  } catch {
    return `${amount.toFixed(2)} ${safeCurrency}`
  }
}

const getBackgroundVisualValue = (theme: SiteTheme | undefined) => {
  if (theme?.backgroundAttachment === 'fixed' && theme.backgroundRepeat === 'repeat-x' && theme.backgroundPosition === 'center top') return 'repeat-x-fixed-top'
  if (theme?.backgroundRepeat === 'repeat') return 'repeat'
  if (theme?.backgroundRepeat === 'repeat-x') return 'repeat-x'
  if (theme?.backgroundRepeat === 'repeat-y') return 'repeat-y'
  if (theme?.backgroundRepeat === 'no-repeat' && theme.backgroundFit === 'full_width') return 'full_width'
  if (theme?.backgroundRepeat === 'no-repeat' && theme.backgroundFit === 'contain') return 'no-repeat'
  return 'cover'
}

const backgroundVisualPatch = (value: string): Partial<SiteTheme> => {
  if (value === 'full_width') return { backgroundFit: 'full_width', backgroundRepeat: 'no-repeat', backgroundPosition: 'center top', backgroundAttachment: 'scroll' }
  if (value === 'no-repeat') return { backgroundFit: 'contain', backgroundRepeat: 'no-repeat', backgroundPosition: 'center center', backgroundAttachment: 'scroll' }
  if (value === 'repeat') return { backgroundFit: 'auto', backgroundRepeat: 'repeat', backgroundPosition: 'center top', backgroundAttachment: 'scroll' }
  if (value === 'repeat-x') return { backgroundFit: 'auto', backgroundRepeat: 'repeat-x', backgroundPosition: 'center top', backgroundAttachment: 'scroll' }
  if (value === 'repeat-y') return { backgroundFit: 'auto', backgroundRepeat: 'repeat-y', backgroundPosition: 'left top', backgroundAttachment: 'scroll' }
  if (value === 'repeat-x-fixed-top') return { backgroundFit: 'auto', backgroundRepeat: 'repeat-x', backgroundPosition: 'center top', backgroundAttachment: 'fixed' }
  return { backgroundFit: 'cover', backgroundRepeat: 'no-repeat', backgroundPosition: 'center center', backgroundAttachment: 'scroll' }
}

const getBackgroundSizeCss = (value: string) => {
  if (value === 'contain' || value === 'no-repeat') return 'contain'
  if (value === 'full_width') return '100% auto'
  if (value === 'auto' || value === 'repeat' || value === 'repeat-x' || value === 'repeat-y') return 'auto'
  return 'cover'
}

const isHorizontalAlign = (value: unknown): value is HorizontalAlign =>
  value === 'left' || value === 'center' || value === 'right' || value === 'justify'

const isButtonAlign = (value: unknown): value is ButtonAlign =>
  isHorizontalAlign(value) || value === 'full'

const getHorizontalAlign = (settings: Record<string, unknown>, key: string, fallback: HorizontalAlign = 'left'): HorizontalAlign => {
  const value = settings[key]
  return isHorizontalAlign(value) ? value : fallback
}

const getButtonAlign = (settings: Record<string, unknown>, fallback: ButtonAlign = 'center'): ButtonAlign => {
  const value = settings.buttonAlign
  return isButtonAlign(value) ? value : fallback
}

const getThemeButtonAlign = (theme: SiteTheme | undefined, key: keyof SiteTheme, fallback: ButtonAlign = 'center'): ButtonAlign => {
  const value = theme?.[key]
  return isButtonAlign(value) ? value : fallback
}

const justifyForAlign = (align: HorizontalAlign | ButtonAlign) => {
  if (align === 'center') return 'center'
  if (align === 'right') return 'end'
  if (align === 'full' || align === 'justify') return 'stretch'
  return 'start'
}

const marginVarsForAlign = (align: HorizontalAlign | ButtonAlign) => {
  if (align === 'center') return { left: 'auto', right: 'auto' }
  if (align === 'right') return { left: 'auto', right: '0' }
  if (align === 'justify') return { left: '0', right: '0' }
  return { left: '0', right: align === 'full' ? '0' : 'auto' }
}

const textBoldDefaultBlockTypes = new Set<SiteBlockType>([
  'headline',
  'title',
  'hero',
  'section',
  'benefits',
  'testimonials',
  'services',
  'faq',
  'payment',
  'form_embed',
  'cta'
])

const getParentSectionBlock = (block: SiteBlock, blocks: SiteBlock[]) => {
  const sectionId = getBlockSectionId(block)
  if (!sectionId) return null
  return blocks.find(item => item.id === sectionId && isSectionBlock(item)) || null
}

const getPageTextPaint = (site: PublicSite) =>
  readableTextOnBackground(
    getThemePaint(site.theme, 'textColor', isSiteDark(site) ? AUTO_LIGHT_TEXT : AUTO_DARK_TEXT),
    resolvedPageBg(site),
    isSiteDark(site) ? AUTO_LIGHT_TEXT : AUTO_DARK_TEXT
  )

const getBlockTextAlignFallback = (site: PublicSite, block: SiteBlock, blocks: SiteBlock[] = []): HorizontalAlign => {
  const parent = isLanding(site) && !isTopLevelLandingBlock(block) ? getParentSectionBlock(block, blocks) : null
  if (parent) {
    return getHorizontalAlign(parent.settings || {}, 'textAlign', 'center')
  }

  if (block.blockType === HEADER_PANEL_BLOCK_TYPE) return 'left'
  if (block.blockType === FOOTER_PANEL_BLOCK_TYPE) return 'center'
  if (block.blockType === SECTION_BLOCK_TYPE || block.blockType === 'hero' || block.blockType === 'cta') return 'center'
  if (['benefits', 'testimonials', 'services', 'faq'].includes(block.blockType)) return 'center'
  if (!fieldBlockTypes.has(block.blockType) && ['interactive', 'vsl'].includes(resolveTemplateId(site))) return 'center'
  return 'left'
}

const getBlockFontSizeFallback = (site: PublicSite, block: SiteBlock) => {
  if (isLanding(site)) {
    if (block.blockType === 'hero') return 58
    if (block.blockType === 'headline' || block.blockType === 'title') return 52
    if (block.blockType === 'cta') return 42
    if (block.blockType === SECTION_BLOCK_TYPE || ['benefits', 'testimonials', 'services', 'faq', 'form_embed'].includes(block.blockType)) return 32
    if (block.blockType === 'subheading' || block.blockType === 'subtitle' || block.blockType === 'description') return 20
    if (block.blockType === 'text') return 17
  }

  if (block.blockType === 'headline' || block.blockType === 'title') return 38
  if (block.blockType === 'subheading' || block.blockType === 'subtitle' || block.blockType === 'description') return 18
  return 18
}

const getBlockContentMaxWidthFallback = (site: PublicSite, block: SiteBlock) => {
  if (isLanding(site)) {
    if (block.blockType === 'hero') return 16
    if (['benefits', 'testimonials', 'services', 'faq'].includes(block.blockType)) return 20
    if (block.blockType === 'cta') return 52
    if (block.blockType === 'subheading' || block.blockType === 'subtitle') return 60
    if (block.blockType === 'description') return 58
  }

  if (block.blockType === 'subheading' || block.blockType === 'subtitle' || block.blockType === 'description') return 60
  return 66
}

const getBlockRadiusFallback = (_site: PublicSite, _block: SiteBlock) => 0

const getBlockBorderWidthFallback = (site: PublicSite, block: SiteBlock) => {
  if (block.blockType === 'social_profile') return 0
  if (block.blockType === 'image' || block.blockType === 'video' || block.blockType === 'embed' || block.blockType === 'calendar_embed') return 1
  if (isLanding(site) && ['hero', 'section', 'cta', 'benefits', 'testimonials', 'services', 'faq', 'form_embed', 'social_profile'].includes(block.blockType)) return 0
  return nativeBorderBlockTypes.has(block.blockType) ? 1 : 0
}

const getCardRadiusFallback = (site: PublicSite) => isLanding(site) ? 0 : 8
const getCardBorderWidthFallback = (site: PublicSite) => isLanding(site) ? 0 : 1

const getInheritedBlockStyleSettings = (site: PublicSite, block: SiteBlock, blocks: SiteBlock[]) => {
  const parent = isLanding(site) && !isTopLevelLandingBlock(block) ? getParentSectionBlock(block, blocks) : null
  if (!parent) return {}
  const settings = parent.settings || {}
  const inheritedKeys = [
    'blockText',
    'contentMaxWidth',
    'fontFamily',
    'fontWeight',
    'fontStyle',
    'textDecoration',
    'textTransform',
    'lineHeight',
    'textListStyle',
    'textStrokeColor',
    'textStrokeWidth',
    'textAlign'
  ]

  return inheritedKeys.reduce<Record<string, unknown>>((acc, key) => {
    if (settings[key] !== undefined && settings[key] !== '') acc[key] = settings[key]
    return acc
  }, {})
}

const getPanelStyleSettings = (site: PublicSite, block: SiteBlock, blocks: SiteBlock[]) => {
  const inherited = getInheritedBlockStyleSettings(site, block, blocks)
  const defaults: Record<string, unknown> = {
    textAlign: getBlockTextAlignFallback(site, block, blocks),
    buttonAlign: 'center',
    fontSize: getBlockFontSizeFallback(site, block),
    contentMaxWidth: getBlockContentMaxWidthFallback(site, block),
    blockText: getPageTextPaint(site),
    blockBg: 'transparent',
    blockRadius: getBlockRadiusFallback(site, block),
    blockBorderWidth: getBlockBorderWidthFallback(site, block),
    cardAlign: 'left',
    cardRadius: getCardRadiusFallback(site),
    cardBorderWidth: getCardBorderWidthFallback(site),
    listColumns: 3,
    mediaAlign: 'center',
    mediaWidth: 100,
    mediaRadius: 18,
    fieldBg: 'transparent',
    fieldBorder: '#dbe3ef',
    fieldWidth: 100,
    fieldRadius: 12,
    buttonRadius: 28,
    buttonHeight: 54,
    buttonPaddingX: 28,
    buttonFontSize: 16,
    buttonLineHeight: '',
    buttonBorderWidth: 1
  }

  if (textBoldDefaultBlockTypes.has(block.blockType)) defaults.fontWeight = 'bold'

  return {
    ...defaults,
    ...inherited,
    ...(block.settings || {})
  }
}

const hasSpacingSideValue = (settings: Record<string, unknown>, base: SpacingBase) =>
  spacingSides.some(side => settings[`${base}${side.id}`] !== undefined)

const getSpacingValue = (
  settings: Record<string, unknown>,
  base: SpacingBase,
  side: typeof spacingSides[number]['id'],
  fallback: number,
  min: number,
  max: number
) => {
  const sideKey = `${base}${side}`
  if (settings[sideKey] !== undefined) return getSettingNumber(settings, sideKey, fallback, min, max)
  if (settings[base] !== undefined) return getSettingNumber(settings, base, fallback, min, max)
  return fallback
}

const getSpacingShorthand = (
  values: Record<typeof spacingSides[number]['id'], number>
) => spacingSides
  .map(side => `${values[side.id]}px`)
  .join(' ')

const getSpacingValues = (
  settings: Record<string, unknown>,
  base: SpacingBase,
  fallback: number,
  min: number,
  max: number
) => spacingSides
  .reduce<Record<typeof spacingSides[number]['id'], number>>((acc, side) => {
    acc[side.id] = getSpacingValue(settings, base, side.id, fallback, min, max)
    return acc
  }, { Top: fallback, Right: fallback, Bottom: fallback, Left: fallback })

const hasNegativeSpacing = (values: Record<typeof spacingSides[number]['id'], number>) =>
  spacingSides.some(side => values[side.id] < 0)

const getPositiveSpacing = (values: Record<typeof spacingSides[number]['id'], number>) =>
  spacingSides.reduce<Record<typeof spacingSides[number]['id'], number>>((acc, side) => {
    acc[side.id] = Math.max(0, values[side.id])
    return acc
  }, { Top: 0, Right: 0, Bottom: 0, Left: 0 })

const getNegativeSpacing = (values: Record<typeof spacingSides[number]['id'], number>) =>
  spacingSides.reduce<Record<typeof spacingSides[number]['id'], number>>((acc, side) => {
    acc[side.id] = Math.min(0, values[side.id])
    return acc
  }, { Top: 0, Right: 0, Bottom: 0, Left: 0 })

const combineSpacingValues = (
  first: Record<typeof spacingSides[number]['id'], number>,
  second: Record<typeof spacingSides[number]['id'], number>
) => spacingSides.reduce<Record<typeof spacingSides[number]['id'], number>>((acc, side) => {
  acc[side.id] = first[side.id] + second[side.id]
  return acc
}, { Top: 0, Right: 0, Bottom: 0, Left: 0 })

// Mirrors backend renderBlockStyleVars so per-block overrides resolve to the same
// CSS variables the published .rstk-block-style wrapper consumes.
type BlockCanvasStyleContext = {
  site?: PublicSite | null
  parentBlock?: SiteBlock | null
}

// Fondo de contraste de página para blockText (content #8): MISMO helper
// compartido que usa el renderer público (pageBg sólido del usuario o el del
// template — nunca el primer stop de un gradiente ni swatches hardcodeados).
// Memo por sitio: el estado de página no cambia entre bloques del mismo render.
const canvasContrastBgCache = new WeakMap<object, string>()

const getCanvasPageContrastBg = (site?: PublicSite | null): string => {
  if (!site) return ''
  const cached = canvasContrastBgCache.get(site)
  if (cached !== undefined) return cached
  const value = blockTextContrastBackground(computeSitePageRenderState(site as unknown as SiteLike))
  canvasContrastBgCache.set(site, value)
  return value
}

const buildCanvasBlockVarsCtx = (context: BlockCanvasStyleContext = {}) => ({
  parentBlock: context.parentBlock as unknown as SiteBlockLike | null,
  pageBg: getCanvasPageContrastBg(context.site)
})

// Consumidor directo del contrato compartido (content #10/#11: semántica del
// publicado — números no finitos se omiten, posiciones sanitizadas, paints sin
// fallback blanco). No agrega variables propias del editor.
const getBlockCanvasStyle = (block: SiteBlock, context: BlockCanvasStyleContext = {}): React.CSSProperties =>
  buildBlockStyleVars(block as unknown as SiteBlockLike, buildCanvasBlockVarsCtx(context)) as React.CSSProperties

type BlockWrapperMode = 'auto' | 'always'

// Paridad content #3 / form-fields #5: el publicado solo envuelve el bloque en
// div.rstk-block-style cuando hay variables/full-width/video de fondo/oculto
// (blockHasStyleWrapper, compartido). En modo 'auto' el editor espeja ese
// predicado; 'always' se reserva para superficies que en vivo SIEMPRE llevan
// las clases (franjas de sección) y para el overlay de drag de la paleta.
const getBlockStyleClassName = (block: SiteBlock, extra = '', wrapper: BlockWrapperMode = 'auto') => {
  const hasWrapper = wrapper === 'always' || blockHasStyleWrapper(block as unknown as SiteBlockLike)
  return [
    hasWrapper ? buildBlockStyleClassName(block as unknown as SiteBlockLike) : '',
    isBlockHidden(block) ? 'rstkHiddenBlock' : '',
    extra
  ].filter(Boolean).join(' ')
}

const cloneJson = <T,>(value: T): T => {
  try {
    return JSON.parse(JSON.stringify(value)) as T
  } catch {
    return value
  }
}

const editorValuesEqual = (left: unknown, right: unknown) => {
  if (Object.is(left, right)) return true

  try {
    return JSON.stringify(left) === JSON.stringify(right)
  } catch {
    return false
  }
}

const editorPatchHasChanges = (current: Record<string, unknown>, patch: Record<string, unknown>) =>
  Object.entries(patch).some(([key, value]) => !editorValuesEqual(current[key], value))

const normalizePageList = (rawPages: SitePage[] = []): SitePage[] => {
  const seen = new Set<string>()
  const normalized = rawPages
    .map((page, index) => {
      const source = page as SitePage & {
        button_text?: string
        button_subtitle?: string
        meta_capi_enabled?: unknown
        meta_event_name?: string
        meta_trigger?: string
        meta_event_parameters?: SiteMetaEventParameters
        meta_calendar_enabled?: unknown
        meta_calendar_event_name?: string
        meta_calendar_event_parameters?: SiteMetaEventParameters
      }
      const buttonText = typeof (source?.buttonText ?? source?.button_text) === 'string'
        ? String(source.buttonText ?? source.button_text).trim()
        : ''
      const buttonSubtitle = typeof (source?.buttonSubtitle ?? source?.button_subtitle) === 'string'
        ? String(source.buttonSubtitle ?? source.button_subtitle).trim()
        : ''
      const rawMetaTrigger = String(source?.metaTrigger || source?.meta_trigger || '').trim()
      const legacyCalendarTrigger = rawMetaTrigger === 'calendar_schedule'
      const rawMetaEventName = normalizeMetaEventName(source?.metaEventName || source?.meta_event_name, 'none')
      const metaEventName = legacyCalendarTrigger ? 'none' : rawMetaEventName
      const metaCalendarEventName = normalizeMetaEventName(
        source?.metaCalendarEventName || source?.meta_calendar_event_name || (legacyCalendarTrigger ? rawMetaEventName : ''),
        'none'
      )
      const metaCalendarEnabled = (
        normalizeMetaBoolean(source?.metaCalendarEnabled ?? source?.meta_calendar_enabled) ||
        legacyCalendarTrigger
      ) && metaCalendarEventName !== 'none'
      const metaCalendarEventParameters = pruneMetaEventParametersForEvent(
        source?.metaCalendarEventParameters || source?.meta_calendar_event_parameters || source?.metaEventParameters || source?.meta_event_parameters,
        metaCalendarEventName
      )
      const metaEventParameters = pruneMetaEventParametersForEvent(
        source?.metaEventParameters || source?.meta_event_parameters,
        metaEventName
      )
      const metaTrigger: SiteMetaTrigger = rawMetaTrigger === 'form_submit'
        ? 'form_submit'
        : 'page_view'

      return {
        id: page?.id || `${DEFAULT_FUNNEL_PAGE_ID}-${index + 1}`,
        title: page?.title || `Página ${index + 1}`,
        sortOrder: Number.isFinite(Number(page?.sortOrder)) ? Number(page.sortOrder) : index,
        ...(page?.parentPageId ? { parentPageId: page.parentPageId } : {}),
        ...(page?.slug ? { slug: page.slug } : {}),
        ...(buttonText ? { buttonText } : {}),
        ...(buttonSubtitle ? { buttonSubtitle } : {}),
        ...(page?.importedAssetPath ? { importedAssetPath: page.importedAssetPath } : {}),
        ...(page?.importedOriginalTitle ? { importedOriginalTitle: page.importedOriginalTitle } : {}),
        ...(page?.headerTrackingCode !== undefined ? { headerTrackingCode: page.headerTrackingCode } : {}),
        metaCapiEnabled: !legacyCalendarTrigger && normalizeMetaBoolean(source?.metaCapiEnabled ?? source?.meta_capi_enabled),
        metaEventName,
        metaTrigger,
        ...(metaCalendarEnabled ? { metaCalendarEnabled: true, metaCalendarEventName } : {}),
        ...(metaCalendarEnabled && hasMetaEventParameters(metaCalendarEventParameters)
          ? { metaCalendarEventParameters }
          : {}),
        ...(hasMetaEventParameters(metaEventParameters)
          ? { metaEventParameters }
          : {})
      }
    })
    .filter(page => {
      if (!page.id || seen.has(page.id)) return false
      seen.add(page.id)
      return true
    })
    .sort((a, b) => a.sortOrder - b.sortOrder)
    .map((page, index) => ({ ...page, sortOrder: index }))

  return normalized
}

const normalizeFormPages = (site?: PublicSite | null): SitePage[] => {
  const normalized = normalizePageList(Array.isArray(site?.theme?.pages) ? site.theme.pages : [])
  const byId = new Map(normalized.map(page => [page.id, page]))
  const defaults = getDefaultFormPages()
  const contentPages = normalized.filter(page => !isFormFinalPage(page))
  const inputPages = contentPages.length ? contentPages : [byId.get(DEFAULT_FUNNEL_PAGE_ID) || defaults[0]]
  const mergeFinalPage = (page: SitePage): SitePage => {
    const existing = byId.get(page.id)
    return {
      ...page,
      title: existing?.title || page.title,
      ...(existing?.headerTrackingCode !== undefined ? { headerTrackingCode: existing.headerTrackingCode } : {}),
      metaCapiEnabled: Boolean(existing?.metaCapiEnabled),
      metaEventName: normalizeMetaEventName(existing?.metaEventName, 'none'),
      metaTrigger: normalizeMetaTrigger(existing?.metaTrigger),
      ...(existing?.metaCalendarEnabled && existing.metaCalendarEventName && existing.metaCalendarEventName !== 'none'
        ? {
            metaCalendarEnabled: true,
            metaCalendarEventName: existing.metaCalendarEventName,
            ...(hasMetaEventParameters(existing.metaCalendarEventParameters)
              ? { metaCalendarEventParameters: pruneMetaEventParametersForEvent(existing.metaCalendarEventParameters, existing.metaCalendarEventName) }
              : {})
          }
        : {}),
      ...(hasMetaEventParameters(existing?.metaEventParameters)
        ? { metaEventParameters: pruneMetaEventParametersForEvent(existing?.metaEventParameters, existing?.metaEventName) }
        : {})
    }
  }

  return [
    ...inputPages,
    mergeFinalPage(defaults[1]),
    mergeFinalPage(defaults[2])
  ].map((page, index) => ({ ...page, sortOrder: index }))
}

const normalizeFunnelPages = (site?: PublicSite | null): SitePage[] => {
  if (isImportedHtmlSite(site)) {
    const normalized = normalizePageList(Array.isArray(site?.theme?.pages) ? site.theme.pages : [])
    return normalized.length ? normalized : [{ id: DEFAULT_FUNNEL_PAGE_ID, title: 'Página 1', sortOrder: 0 }]
  }

  if (isStandardForm(site)) return normalizeFormPages(site)

  const normalized = normalizePageList(Array.isArray(site?.theme?.pages) ? site.theme.pages : [])
  return normalized.length ? normalized : [{ id: DEFAULT_FUNNEL_PAGE_ID, title: 'Página 1', sortOrder: 0 }]
}

const getFormContentPages = (pages: SitePage[]) => pages.filter(page => !isFormFinalPage(page))

const getFormActionPages = (site: PublicSite | null | undefined, pages: SitePage[]) => (
  isStandardForm(site)
    ? getFormContentPages(pages)
    : pages.filter(page => !isFormFinalPage(page))
)

const getPageButtonText = (page?: SitePage | null) => (
  typeof page?.buttonText === 'string' ? page.buttonText.trim() : ''
)

const getPageButtonSubtitle = (page?: SitePage | null) => (
  typeof page?.buttonSubtitle === 'string' ? page.buttonSubtitle.trim() : ''
)

const getFormPageForAction = (pages: SitePage[], pageId?: string) => (
  pages.find(page => page.id === pageId) || pages[0] || null
)

const isLastFormActionPage = (site: PublicSite | null | undefined, pages: SitePage[], pageId?: string) => {
  const actionPages = getFormActionPages(site, pages)
  const activePage = actionPages.find(page => page.id === pageId) || getFormPageForAction(actionPages, pageId)
  if (!activePage || !actionPages.length) return true
  return actionPages[actionPages.length - 1]?.id === activePage.id
}

const getFormPageActionLabel = (site: PublicSite | null | undefined, pages: SitePage[], pageId?: string) => {
  const activePage = getFormPageForAction(pages, pageId)
  const explicitText = getPageButtonText(activePage)
  if (explicitText) return explicitText
  const isLastPage = isLastFormActionPage(site, pages, activePage?.id)
  if (isLastPage) return getThemeString(site?.theme, 'submitText') || 'Enviar'
  return isStandardForm(site)
    ? getThemeString(site?.theme, 'continueText') || 'Continuar'
    : getThemeString(site?.theme, 'nextText') || 'Siguiente'
}

const getFormPageActionSubtitle = (site: PublicSite | null | undefined, pages: SitePage[], pageId?: string) => {
  const activePage = getFormPageForAction(pages, pageId)
  const explicitSubtitle = getPageButtonSubtitle(activePage)
  if (explicitSubtitle) return explicitSubtitle
  return isLastFormActionPage(site, pages, activePage?.id)
    ? getThemeString(site?.theme, 'submitSubtitle')
    : ''
}

const normalizeEmbeddedFormPages = (rawPages?: unknown): SitePage[] => {
  const normalized = normalizePageList(Array.isArray(rawPages) ? rawPages as SitePage[] : [])
  const contentPages = getFormContentPages(normalized)
  const pages = contentPages.length ? contentPages : normalized
  return (pages.length ? pages : [makeTemplateFunnelPage(DEFAULT_FUNNEL_PAGE_ID, 'Formulario', 0)])
    .map((page, index) => ({ ...page, sortOrder: index }))
}

const getEmbeddedFormContentPagesFromSite = (site?: PublicSite | null): SitePage[] =>
  normalizeEmbeddedFormPages(site ? normalizeFunnelPages(site) : [])

const getEmbeddedFormPageFields = (fields: SiteBlock[], pages: SitePage[], pageId?: string) => {
  const activePageId = pageId && pages.some(page => page.id === pageId)
    ? pageId
    : pages[0]?.id || DEFAULT_FUNNEL_PAGE_ID
  return fields.filter(field => getBlockPageId(field, pages) === activePageId)
}

const applyPageArrayOrder = (pages: SitePage[]) => (
  pages.map((page, index) => ({ ...page, sortOrder: index }))
)

const getOrderedPagesForSite = (site: PublicSite, nextPages: SitePage[]) => {
  const orderedNextPages = applyPageArrayOrder(nextPages)
  return isStandardForm(site)
    ? normalizeFormPages({ ...site, theme: { ...(site.theme || {}), pages: orderedNextPages } })
    : orderedNextPages
}

const getFormAddPageIndex = (site: PublicSite, pages: SitePage[]) => (
  isStandardForm(site)
    ? pages.findIndex(isFormFinalPage) >= 0
      ? pages.findIndex(isFormFinalPage)
      : pages.length
    : pages.length
)

const makeFunnelPage = (index: number, extra?: Partial<SitePage>): SitePage => ({
  id: createRistakId('site_page'),
  title: `Página ${index + 1}`,
  sortOrder: index,
  metaCapiEnabled: false,
  metaEventName: 'none',
  metaTrigger: 'page_view',
  ...extra
})

const normalizePagesForSave = (pages: SitePage[]) =>
  pages.map((page, index) => ({
    id: page.id,
    title: page.title || `Página ${index + 1}`,
    sortOrder: index,
    ...(page.parentPageId ? { parentPageId: page.parentPageId } : {}),
    ...(page.slug ? { slug: page.slug } : {}),
    ...(getPageButtonText(page) ? { buttonText: getPageButtonText(page) } : {}),
    ...(getPageButtonSubtitle(page) ? { buttonSubtitle: getPageButtonSubtitle(page) } : {}),
    ...(page.importedAssetPath ? { importedAssetPath: page.importedAssetPath } : {}),
    ...(page.importedOriginalTitle ? { importedOriginalTitle: page.importedOriginalTitle } : {}),
    ...(page.headerTrackingCode !== undefined ? { headerTrackingCode: page.headerTrackingCode } : {}),
    metaCapiEnabled: Boolean(page.metaCapiEnabled),
    metaEventName: normalizeMetaEventName(page.metaEventName, 'none'),
    metaTrigger: normalizeMetaTrigger(page.metaTrigger),
    ...(page.metaCalendarEnabled && page.metaCalendarEventName && page.metaCalendarEventName !== 'none'
      ? {
          metaCalendarEnabled: true,
          metaCalendarEventName: page.metaCalendarEventName,
          ...(hasMetaEventParameters(page.metaCalendarEventParameters)
            ? { metaCalendarEventParameters: pruneMetaEventParametersForEvent(page.metaCalendarEventParameters, page.metaCalendarEventName) }
            : {})
        }
      : {}),
    ...(hasMetaEventParameters(page.metaEventParameters)
      ? { metaEventParameters: pruneMetaEventParametersForEvent(page.metaEventParameters, page.metaEventName) }
      : {})
  }))

// --- Website page hierarchy (subpages) helpers ---
const MAX_WEBSITE_PAGE_DEPTH = 2 // top-level = 0, subpage = 1, sub-subpage = 2

const getSitePageMode = (site?: PublicSite | null): 'funnel' | 'website' =>
  isLanding(site) && !isImportedHtmlSite(site) && site?.theme?.pageMode === 'website' ? 'website' : 'funnel'

// Landings visuales e HTML importados comparten rutas limpias por página.
const hasRoutableSitePages = (site?: PublicSite | null) => site?.siteType === 'landing_page'

const getPageDepth = (page: SitePage | undefined, pages: SitePage[]): number => {
  if (!page) return 0
  const byId = new Map(pages.map(p => [p.id, p]))
  const seen = new Set<string>()
  let depth = 0
  let current: SitePage | undefined = page
  while (current?.parentPageId) {
    if (seen.has(current.id)) break
    seen.add(current.id)
    const parent = byId.get(current.parentPageId)
    if (!parent) break
    depth += 1
    current = parent
  }
  return depth
}

const getDescendantPageIds = (pageId: string, pages: SitePage[]): string[] => {
  const result: string[] = []
  const collect = (parentId: string) => {
    for (const page of pages) {
      if ((page.parentPageId || '') === parentId) {
        result.push(page.id)
        collect(page.id)
      }
    }
  }
  collect(pageId)
  return result
}

// Height of a page's subtree relative to the page itself (0 = no subpages).
const getPageSubtreeHeight = (pageId: string, pages: SitePage[]): number => {
  const children = pages.filter(page => (page.parentPageId || '') === pageId)
  if (!children.length) return 0
  return 1 + Math.max(...children.map(child => getPageSubtreeHeight(child.id, pages)))
}

// A page can demote (become a subpage) when a previous sibling exists and the
// moved subtree still fits within MAX_WEBSITE_PAGE_DEPTH.
const getPreviousSiblingPage = (page: SitePage, pages: SitePage[]): SitePage | null => {
  const siblings = pages.filter(item => (item.parentPageId || '') === (page.parentPageId || ''))
  const index = siblings.findIndex(item => item.id === page.id)
  return index > 0 ? siblings[index - 1] : null
}

const canPromoteWebsitePage = (page: SitePage, pages: SitePage[]) => getPageDepth(page, pages) > 0

const canDemoteWebsitePage = (page: SitePage, pages: SitePage[]) => {
  const previousSibling = getPreviousSiblingPage(page, pages)
  if (!previousSibling) return false
  return getPageDepth(page, pages) + 1 + getPageSubtreeHeight(page.id, pages) <= MAX_WEBSITE_PAGE_DEPTH
}

// Flatten pages into render order: each top-level page is followed by its
// descendants (depth-first), so the dropdown can render an indented tree.
const buildOrderedPageTree = (pages: SitePage[]): Array<{ page: SitePage; depth: number }> => {
  const childrenOf = (parentId: string) =>
    pages.filter(page => (page.parentPageId || '') === parentId).sort((a, b) => a.sortOrder - b.sortOrder)
  const result: Array<{ page: SitePage; depth: number }> = []
  const placed = new Set<string>()
  const walk = (parentId: string, depth: number) => {
    for (const page of childrenOf(parentId)) {
      if (placed.has(page.id)) continue
      placed.add(page.id)
      result.push({ page, depth })
      walk(page.id, depth + 1)
    }
  }
  walk('', 0)
  // Defensive: surface any orphaned page (missing parent) as top-level.
  for (const page of pages) {
    if (!placed.has(page.id)) result.push({ page, depth: 0 })
  }
  return result
}

// Segmentos reservados que NO pueden ser slug de una página: chocarían con el
// marcador de bypass /test o con rutas internas del sitio público.
const RESERVED_PAGE_SLUGS = new Set(['test', 'preview', 'api', 'webhook', 'pay', 'collect', 'assets'])
const AUTO_PAGE_ROUTE_PREFIX = 'rstk'

const formatAutoPageSlug = (index: number) =>
  `${AUTO_PAGE_ROUTE_PREFIX}${String(index).padStart(2, '0')}`

const getNextAutoPageSlug = (used: Set<string>) => {
  let index = 1
  let slug = formatAutoPageSlug(index)
  while (used.has(slug) || RESERVED_PAGE_SLUGS.has(slug)) {
    index += 1
    slug = formatAutoPageSlug(index)
  }
  return slug
}

const getUniqueSiblingPageSlug = (rawSlug: string, used: Set<string>) => {
  const baseSlug = normalizeRouteInput(rawSlug) || 'pagina'
  if (!used.has(baseSlug) && !RESERVED_PAGE_SLUGS.has(baseSlug)) return baseSlug

  let index = 2
  let slug = `${baseSlug}-${index}`
  while (used.has(slug) || RESERVED_PAGE_SLUGS.has(slug)) {
    index += 1
    slug = `${baseSlug}-${index}`
  }
  return slug
}

// Ensure every page has a slug unique among its siblings (same parent). Pages
// whose slug is empty get a neutral generated route (rstk01, rstk02...). Used
// before saving a routable landing (funnel o website) so las URLs limpias por
// página sean válidas sin heredar /sitio-01 ni títulos cambiantes.
const ensureWebsiteSlugs = (pages: SitePage[], rootSlugReservations = new Set<string>()): SitePage[] => {
  const usedByParent = new Map<string, Set<string>>()
  return pages.map(page => {
    const parentKey = page.parentPageId || ''
    if (!usedByParent.has(parentKey)) usedByParent.set(parentKey, new Set())
    const used = usedByParent.get(parentKey) as Set<string>
    const currentSlug = normalizeRouteInput(page.slug || '')
    const autoUsed = parentKey === ''
      ? new Set([...used, ...rootSlugReservations])
      : used
    const slug = currentSlug
      ? getUniqueSiblingPageSlug(currentSlug, used)
      : getNextAutoPageSlug(autoUsed)
    used.add(slug)
    return normalizeRouteInput(page.slug || '') === slug ? page : { ...page, slug }
  })
}

// Segmento de slug efectivo de una página para el preview de ruta: slug propio, o
// derivado del título, o 'pagina'. Espeja pageSlugFor del backend.
const getPageSlugSegment = (page: SitePage): string =>
  normalizeRouteInput(page.slug || '') || normalizeRouteInput(page.title || '') || 'pagina'

const getRootPageSlugReservations = (sites: PublicSite[], currentSiteId: string) => {
  const slugs = new Set<string>()
  sites.forEach(site => {
    if (site.id === currentSiteId || !hasRoutableSitePages(site)) return
    normalizeFunnelPages(site)
      .filter(page => !page.parentPageId)
      .forEach(page => {
        const slug = getPageSlugSegment(page)
        if (slug) slugs.add(slug)
      })
  })
  return slugs
}

const getNextPageSlugForParent = (
  pages: SitePage[],
  parentPageId = '',
  rootSlugReservations = new Set<string>()
) => {
  const used = new Set<string>()
  if (!parentPageId) rootSlugReservations.forEach(slug => used.add(slug))
  pages
    .filter(page => (page.parentPageId || '') === parentPageId)
    .forEach(page => {
      const slug = normalizeRouteInput(page.slug || '')
      if (slug) used.add(slug)
    })
  return getNextAutoPageSlug(used)
}

// Cadena de slugs desde la raíz hasta la página (incluida), siguiendo parentPageId.
// Se usa para construir el preview de la URL (jerárquica) en modo "Sitio web".
const getPageSlugChain = (pages: SitePage[], page: SitePage): string[] => {
  const byId = new Map(pages.map(p => [p.id, p]))
  const chain: string[] = []
  const seen = new Set<string>()
  let current: SitePage | undefined = page
  while (current && !seen.has(current.id)) {
    seen.add(current.id)
    chain.unshift(getPageSlugSegment(current))
    current = current.parentPageId ? byId.get(current.parentPageId) : undefined
  }
  return chain
}

const getPageRoutePath = (pages: SitePage[], page: SitePage): string => {
  const chain = getPageSlugChain(pages, page)
  return `/${(chain.length ? chain : [getPageSlugSegment(page)]).join('/')}`
}

const getOfficialPageRoutePath = (site: PublicSite | null | undefined, domainConfig: SitesDomainConfig, pages: SitePage[], page: SitePage): string =>
  isDefaultPublicRoutePage(site, domainConfig, page.id) ? '/' : getPageRoutePath(pages, page)

const getPageRoutePrefix = (pages: SitePage[], page: SitePage): string => {
  const chain = getPageSlugChain(pages, page)
  const parentSegments = chain.slice(0, -1)
  return parentSegments.length ? `/${parentSegments.join('/')}/` : '/'
}

const buildLivePublicPageUrl = (
  site: PublicSite,
  domainConfig: SitesDomainConfig,
  pages: SitePage[],
  page: SitePage,
  options: { noTrack?: boolean } = {}
) => {
  const url = domainConfig.domain ? `https://${domainConfig.domain}${getOfficialPageRoutePath(site, domainConfig, pages, page)}` : ''
  return options.noTrack ? appendNoTrackToUrl(url) : url
}

const getBlockPageId = (block: SiteBlock, pages: SitePage[]) => {
  const pageId = getSettingString(block.settings || {}, 'pageId')
  return pages.some(page => page.id === pageId) ? pageId : pages[0]?.id || DEFAULT_FUNNEL_PAGE_ID
}

const getHeaderScope = (block?: SiteBlock | null): HeaderScope => (
  block?.blockType === HEADER_PANEL_BLOCK_TYPE &&
  (getSettingString(block.settings || {}, 'headerScope') || getSettingString(block.settings || {}, 'header_scope')) === HEADER_SCOPE_GLOBAL
    ? HEADER_SCOPE_GLOBAL
    : HEADER_SCOPE_PAGE
)

const isGlobalHeaderBlock = (block?: SiteBlock | null) => (
  Boolean(block && block.blockType === HEADER_PANEL_BLOCK_TYPE && getHeaderScope(block) === HEADER_SCOPE_GLOBAL)
)

const isSectionBlock = (block?: SiteBlock | null) => block?.blockType === SECTION_BLOCK_TYPE
const isPanelBlock = (block?: SiteBlock | null) => Boolean(block && PANEL_BLOCK_TYPES.has(block.blockType))
const isTopLevelLandingBlock = (block?: SiteBlock | null) => isSectionBlock(block) || isPanelBlock(block)
const isPopupBlock = (block?: SiteBlock | null) => {
  if (!block) return false
  const settings = block.settings || {}
  return getSettingString(settings, 'popupId') === POPUP_SURFACE_ID ||
    getSettingString(settings, 'renderLocation') === 'popup'
}

const isVideoActionKind = (value: unknown): value is VideoActionKind =>
  videoActionKinds.includes(value as VideoActionKind)

const isVideoActionBeforeState = (value: unknown): value is VideoActionBeforeState =>
  videoActionBeforeStates.includes(value as VideoActionBeforeState)

const isVideoActionTriggerType = (value: unknown): value is VideoActionTriggerType =>
  videoActionTriggerTypes.includes(value as VideoActionTriggerType)

const makeVideoActionId = () => createRistakId('site_video_action')

const clampVideoActionTime = (value: unknown) => {
  const number = Number(value)
  if (!Number.isFinite(number)) return 0
  return Math.max(0, Math.min(86399, Math.round(number)))
}

const clampVideoActionPercent = (value: unknown) => {
  const number = Number(value)
  if (!Number.isFinite(number)) return 50
  return Math.max(1, Math.min(100, Math.round(number)))
}

const normalizeVideoActionTriggerType = (value: unknown): VideoActionTriggerType =>
  isVideoActionTriggerType(value) ? value : 'timeline_reached'

const getRecommendedVideoActionBefore = (action: VideoActionKind): VideoActionBeforeState => {
  if (action === 'show' || action === 'show_popup' || action === 'open_form' || action === 'reveal_form_action') return 'hidden'
  if (action === 'hide') return 'visible'
  return 'unchanged'
}

const normalizeVideoActionRepeatMode = (value: unknown): VideoFormGateRepeatMode =>
  videoFormGateRepeatModeOptions.some(option => option.value === value) ? value as VideoFormGateRepeatMode : 'every_visit'

const clampVideoActionStorageValue = (value: unknown) => {
  const number = Number(value)
  if (!Number.isFinite(number)) return 30
  return Math.min(730, Math.max(1, Math.round(number)))
}

const getVideoFormGateAnimation = (settings: Record<string, unknown> = {}): VideoFormGateAnimation => {
  const animation = getSettingString(settings, 'videoFormGateAnimation') as VideoFormGateAnimation
  return videoFormGateAnimationOptions.some(option => option.value === animation) ? animation : 'fade'
}

const getVideoFormGateFinalAction = (settings: Record<string, unknown> = {}): VideoFormGateCompletionAction => {
  const action = getSettingString(settings, 'videoFormGateCompletionAction') as VideoFormGateCompletionAction
  if (videoFormGateCompletionActionOptions.some(option => option.value === action)) return action
  const embeddedTheme = getVideoFormGateEmbeddedTheme(settings)
  if (embeddedTheme.formCompletionAction === 'redirect_qualified' && embeddedTheme.formQualifiedRedirectUrl) return 'redirect'
  return 'continue_video'
}

const getVideoFormGateRepeatMode = (settings: Record<string, unknown> = {}): VideoFormGateRepeatMode => {
  const mode = getSettingString(settings, 'videoFormGateRepeatMode') as VideoFormGateRepeatMode
  return videoFormGateRepeatModeOptions.some(option => option.value === mode) ? mode : 'every_visit'
}

const getVideoFormGateStorageUnit = (settings: Record<string, unknown> = {}): VideoFormGateStorageUnit => (
  getSettingString(settings, 'videoFormGateStorageUnit') === 'months' ? 'months' : 'days'
)

const getVideoFormGateStorageValue = (settings: Record<string, unknown> = {}) => (
  getSettingNumber(settings, 'videoFormGateStorageValue', 30, 1, 730)
)

const getVideoFormGateVideoBackground = (settings: Record<string, unknown> = {}) => (
  normalizeCssPaint(
    getSettingString(settings, 'videoFormGateVideoBackground') || getSettingString(settings, 'video_form_gate_video_background'),
    getSettingString(settings, 'videoFormGateThemeMode') === 'light' || getSettingString(settings, 'video_form_gate_theme_mode') === 'light'
      ? LIGHT_VIDEO_FORM_GATE_VIDEO_BACKGROUND
      : DEFAULT_VIDEO_FORM_GATE_VIDEO_BACKGROUND
  )
)

const getVideoFormGateThemeMode = (settings: Record<string, unknown> = {}): VideoFormGateThemeMode => {
  const raw = getSettingString(settings, 'videoFormGateThemeMode') || getSettingString(settings, 'video_form_gate_theme_mode')
  return raw === 'light' ? 'light' : DEFAULT_VIDEO_FORM_GATE_THEME_MODE
}

const getVideoFormGateThemePreset = (mode: VideoFormGateThemeMode): Partial<SiteTheme> => ({
  ...VIDEO_FORM_GATE_THEME_PRESETS[mode]
})

const getVideoFormGateThemePalette = (mode: VideoFormGateThemeMode): Partial<SiteTheme> => {
  const preset = getVideoFormGateThemePreset(mode)
  const palette: Record<string, unknown> = {}

  VIDEO_FORM_GATE_THEME_PALETTE_KEYS.forEach((key) => {
    const value = preset[key]
    if (value !== undefined) palette[key] = value
  })

  return palette as Partial<SiteTheme>
}

const getVideoFormGateThemeModePatch = (
  currentTheme: Partial<SiteTheme>,
  currentMode: VideoFormGateThemeMode,
  nextMode: VideoFormGateThemeMode
): Partial<SiteTheme> => {
  const currentPresetPalette = getVideoFormGateThemePalette(currentMode)
  const nextPresetPalette = getVideoFormGateThemePalette(nextMode)
  const patch: Record<string, unknown> = {}

  VIDEO_FORM_GATE_THEME_PALETTE_KEYS.forEach((key) => {
    const currentValue = currentTheme[key]
    const nextValue = nextPresetPalette[key]
    const isPresetValue = videoFormGateThemeModeOptions.some((option) => (
      getVideoFormGateThemePalette(option.value)[key] === currentValue
    ))
    const shouldUsePreset = currentValue === undefined || currentValue === currentPresetPalette[key] || isPresetValue

    if (shouldUsePreset && nextValue !== undefined) patch[key] = nextValue
  })

  return patch as Partial<SiteTheme>
}

const getVideoFormGateThemeVideoBackground = (mode: VideoFormGateThemeMode) => (
  mode === 'light' ? LIGHT_VIDEO_FORM_GATE_VIDEO_BACKGROUND : DEFAULT_VIDEO_FORM_GATE_VIDEO_BACKGROUND
)

const getVideoFormGateCompletionTargetIds = (settings: Record<string, unknown> = {}) => {
  const rawIds = Array.isArray(settings.videoFormGateCompletionTargetIds)
    ? settings.videoFormGateCompletionTargetIds
    : Array.isArray(settings.video_form_gate_completion_target_ids)
      ? settings.video_form_gate_completion_target_ids
      : []
  const ids = rawIds
    .map(value => String(value || '').trim())
    .filter(Boolean)
  const singleId = getSettingString(settings, 'videoFormGateCompletionTargetId') || getSettingString(settings, 'video_form_gate_completion_target_id')
  if (singleId) ids.unshift(singleId)
  return [...new Set(ids)]
}

const getVideoActionTargetIdsFromSource = (source: Record<string, unknown>) => {
  const rawIds = Array.isArray(source.targetBlockIds)
    ? source.targetBlockIds
    : Array.isArray(source.target_block_ids)
      ? source.target_block_ids
      : Array.isArray(source.targetIds)
        ? source.targetIds
        : Array.isArray(source.target_ids)
          ? source.target_ids
          : []
  const ids = rawIds
    .map(value => String(value || '').trim())
    .filter(Boolean)
  const singleId = getSettingString(source, 'targetBlockId') ||
    getSettingString(source, 'target_block_id') ||
    getSettingString(source, 'targetId') ||
    getSettingString(source, 'target_id')
  if (singleId) ids.unshift(singleId)
  return [...new Set(ids)]
}

const normalizeVideoActionRule = (value: unknown, _index = 0): VideoActionRule | null => {
  if (!value || typeof value !== 'object') return null
  const source = value as Record<string, unknown>
  const trigger = source.trigger && typeof source.trigger === 'object'
    ? source.trigger as Record<string, unknown>
    : {}
  const triggerType = normalizeVideoActionTriggerType(
    source.triggerType ?? source.trigger_type ?? trigger.type
  )
  const legacyTimeSeconds = clampVideoActionTime(source.timeSeconds ?? source.time_seconds ?? source.time)
  const rawTriggerValue = source.triggerValue ?? source.trigger_value ?? trigger.value
  const triggerValue = triggerType === 'unique_watched_percent'
    ? clampVideoActionPercent(rawTriggerValue ?? 50)
    : clampVideoActionTime(rawTriggerValue ?? legacyTimeSeconds)
  const action = isVideoActionKind(source.action) ? source.action : 'show'
  const normalizedTriggerType: VideoActionTriggerType = action === 'open_video_form' ? 'timeline_reached' : triggerType
  const normalizedTriggerValue = action === 'open_video_form' && triggerType !== 'timeline_reached'
    ? legacyTimeSeconds
    : triggerValue
  const sourceTargetBlockIds = getVideoActionTargetIdsFromSource(source)
  const targetBlockIds = action === 'show_popup'
    ? [POPUP_SURFACE_ID]
    : action === 'open_video_form'
      ? []
      : sourceTargetBlockIds
  const targetBlockId = targetBlockIds[0] || ''
  const before = isVideoActionBeforeState(source.before) ? source.before : getRecommendedVideoActionBefore(action)
  const id = getSettingString(source, 'id') || makeVideoActionId()
  const targetPageId = getSettingString(source, 'targetPageId') || getSettingString(source, 'target_page_id')
  const redirectUrl = getSettingString(source, 'redirectUrl') || getSettingString(source, 'redirect_url')
  const rawMetaEventName = getSettingString(source, 'metaEventName') || getSettingString(source, 'meta_event_name')
  const metaEventName = action === 'meta_event'
    ? normalizeMetaEventName(rawMetaEventName, 'Lead')
    : ''
  const rawMetaEventParameters = (
    source.metaEventParameters && typeof source.metaEventParameters === 'object'
      ? source.metaEventParameters
      : source.meta_event_parameters && typeof source.meta_event_parameters === 'object'
        ? source.meta_event_parameters
        : undefined
  ) as SiteMetaEventParameters | undefined

  return {
    id,
    timeSeconds: normalizedTriggerType === 'timeline_reached' ? normalizedTriggerValue : legacyTimeSeconds,
    triggerType: normalizedTriggerType,
    triggerValue: normalizedTriggerValue,
    targetBlockId,
    targetBlockIds,
    action,
    before,
    value: getSettingString(source, 'value'),
    targetPageId,
    redirectUrl,
    pauseUntilComplete: source.pauseUntilComplete === true || source.pause_until_complete === true,
    ...(action === 'meta_event' ? {
      metaCapiEnabled: source.metaCapiEnabled !== false && source.meta_capi_enabled !== false,
      metaEventName,
      metaEventParameters: pruneMetaEventParametersForEvent(rawMetaEventParameters, metaEventName)
    } : {}),
    ...(action === 'reveal_form_action' ? {
      repeatMode: normalizeVideoActionRepeatMode(source.repeatMode ?? source.repeat_mode),
      storageValue: clampVideoActionStorageValue(source.storageValue ?? source.storage_value),
      storageUnit: (getSettingString(source, 'storageUnit') || getSettingString(source, 'storage_unit')) === 'months' ? 'months' : 'days'
    } : {})
  }
}

const getVideoActionRules = (settings: Record<string, unknown> = {}) => {
  const source = Array.isArray(settings[VIDEO_ACTIONS_SETTING_KEY]) ? settings[VIDEO_ACTIONS_SETTING_KEY] as unknown[] : []
  const rules = source
    .map(normalizeVideoActionRule)
    .filter((rule): rule is VideoActionRule => Boolean(rule))
  const hasExplicitVideoFormRule = rules.some(rule => rule.action === 'open_video_form')
  if (settings.videoFormGateEnabled === true && !hasExplicitVideoFormRule) {
    const gateRule = normalizeVideoActionRule({
      id: VIDEO_FORM_GATE_ACTION_ID,
      timeSeconds: settings.videoFormGateTriggerSeconds,
      action: 'open_video_form',
      before: 'unchanged'
    }, rules.length)
    if (gateRule) rules.push(gateRule)
  }
  return rules.sort((a, b) => a.timeSeconds - b.timeSeconds)
}

const formatVideoActionTime = (value: unknown) => {
  const totalSeconds = clampVideoActionTime(value)
  const minutes = Math.floor(totalSeconds / 60)
  const seconds = totalSeconds % 60
  return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`
}

const parseVideoActionTimeInput = (value = '') => {
  const clean = value.trim()
  if (!clean) return 0
  const parts = clean.split(':').map(part => part.trim())
  if (parts.length === 1) return clampVideoActionTime(Number(parts[0]))
  const minutes = Number(parts[0])
  const seconds = Number(parts[1])
  if (!Number.isFinite(minutes) || !Number.isFinite(seconds)) return 0
  return clampVideoActionTime(minutes * 60 + seconds)
}

const formatVideoActionTriggerValue = (rule: VideoActionRule) => (
  rule.triggerType === 'unique_watched_percent'
    ? `${clampVideoActionPercent(rule.triggerValue)}%`
    : formatVideoActionTime(rule.triggerValue)
)

const getVideoActionTriggerConditionText = (rule: VideoActionRule, videoLabel = 'video') => {
  if (rule.triggerType === 'playback_seconds') {
    return `el visitante haya reproducido el ${videoLabel} durante ${formatVideoActionTime(rule.triggerValue)}`
  }
  if (rule.triggerType === 'unique_watched_percent') {
    return `el visitante haya visto ${clampVideoActionPercent(rule.triggerValue)}% del contenido del ${videoLabel}`
  }
  return `el ${videoLabel} llegue a ${formatVideoActionTime(rule.triggerValue)}`
}

const getVideoActionTriggerHint = (triggerType: VideoActionTriggerType) => {
  if (triggerType === 'playback_seconds') {
    return 'Solo suma mientras el video se reproduce; adelantar la barra no cuenta.'
  }
  if (triggerType === 'unique_watched_percent') {
    return 'Cuenta fragmentos distintos vistos; adelantar o repetir la misma parte no aumenta el porcentaje.'
  }
  return 'Se activa al llegar a ese punto del video; adelantar la barra hasta ahí también cuenta.'
}

const getVideoActionTargetKindLabel = (block: SiteBlock) => {
  if (block.blockType === 'button' || block.blockType === 'cta' || block.blockType === 'hero') return 'Botón'
  if (block.blockType === 'form_embed' || fieldBlockTypes.has(block.blockType)) return 'Formulario'
  if (block.blockType === SECTION_BLOCK_TYPE) return 'Sección'
  if (block.blockType === 'image') return 'Imagen'
  if (['headline', 'title', 'subheading', 'subtitle', 'description', 'text'].includes(block.blockType)) return 'Texto'
  if (block.blockType === 'calendar_embed') return 'Agenda'
  if (block.blockType === 'video') return 'Video'
  return blockLabels[block.blockType] || 'Otro bloque'
}

const getReadableBlockLabel = (block?: SiteBlock | null) => (
  block?.label || block?.content || (block?.blockType ? blockLabels[block.blockType] : '') || 'Elemento'
).trim()

const getElementPanelName = (block: SiteBlock) =>
  getReadableBlockLabel(block) || getBlockInternalName(block) || 'Elemento'

const getElementPanelDetail = (block: SiteBlock) => {
  const internalName = getBlockInternalName(block)
  const typeLabel = blockLabels[block.blockType] || 'Elemento'
  return internalName && internalName !== slugifyName(getElementPanelName(block))
    ? `${typeLabel} · ${internalName}`
    : typeLabel
}

const getElementPanelDepth = (block: SiteBlock) =>
  getBlockSectionId(block) && !isTopLevelLandingBlock(block) ? 1 : 0

const buildVideoActionTargetOptions = (
  site: PublicSite,
  blocks: SiteBlock[],
  popupBlocks: SiteBlock[],
  sourceVideoId: string,
  importedPopupDetected = false
): VideoActionTargetOption[] => {
  const seen = new Set<string>()
  const options: VideoActionTargetOption[] = []
  const theme = site.theme || {}
  const popupHasConfiguredContent = [
    theme.popupTitle,
    theme.popupBody,
    theme.popupButtonText,
    theme.popupButtonUrl,
    theme.importedPopupHtml
  ].some(value => String(value || '').trim())
  const popupAvailable = importedPopupDetected || popupBlocks.length > 0 || popupHasConfiguredContent || getPopupTrigger(theme) !== 'never'

  if (popupAvailable) {
    seen.add(POPUP_SURFACE_ID)
    options.push({
      id: POPUP_SURFACE_ID,
      label: 'Popup del sitio',
      kindLabel: 'Popup',
      blockType: 'popup'
    })
  }

  ;[...blocks, ...popupBlocks].forEach(block => {
    if (!block || block.id === sourceVideoId || seen.has(block.id)) return
    seen.add(block.id)
    const kindLabel = getVideoActionTargetKindLabel(block)
    options.push({
      id: block.id,
      label: getReadableBlockLabel(block),
      kindLabel,
      blockType: block.blockType
    })
  })

  return options
}

const getVideoActionTargetLabel = (targetId: string, targets: VideoActionTargetOption[]) =>
  targets.find(target => target.id === targetId)?.label || (targetId === POPUP_SURFACE_ID ? 'Popup del sitio' : 'Elemento')

const getVideoActionTargetIds = (rule: VideoActionRule) => (
  (Array.isArray(rule.targetBlockIds) && rule.targetBlockIds.length ? rule.targetBlockIds : (rule.targetBlockId ? [rule.targetBlockId] : []))
    .map(id => String(id || '').trim())
    .filter(Boolean)
)

const getVideoActionTargetsLabel = (rule: VideoActionRule, targets: VideoActionTargetOption[]) => {
  const ids = getVideoActionTargetIds(rule).filter(id => id !== POPUP_SURFACE_ID)
  if (rule.action === 'show_popup') return 'Popup del sitio'
  if (!ids.length) return 'Elemento'
  const labels = ids.map(id => getVideoActionTargetLabel(id, targets))
  if (labels.length <= 2) return labels.join(' y ')
  return `${labels.slice(0, 2).join(', ')} y ${labels.length - 2} más`
}

const getVideoActionPageLabel = (pageId: string | undefined, pages: SitePage[]) =>
  pages.find(page => page.id === pageId)?.title || (pageId ? 'Página del sitio' : 'elige una página')

const getVideoActionRuleText = (rule: VideoActionRule, targets: VideoActionTargetOption[], pages: SitePage[] = []) => {
  const targetLabel = getVideoActionTargetsLabel(rule, targets)
  const triggerCondition = getVideoActionTriggerConditionText(rule)
  if (rule.action === 'open_video_form') {
    return `Cuando ${triggerCondition}, abrir formulario de video.`
  }
  if (rule.action === 'show_popup') {
    return `Cuando ${triggerCondition}, mostrar popup.`
  }
  if (rule.action === 'site_page') {
    return `Cuando ${triggerCondition}, redirigir a ${getVideoActionPageLabel(rule.targetPageId, pages)}.`
  }
  if (rule.action === 'redirect') {
    return `Cuando ${triggerCondition}, redirigir a ${rule.redirectUrl || 'URL destino'}.`
  }
  if (rule.action === 'meta_event') {
    return `Cuando ${triggerCondition}, disparar ${normalizeMetaEventName(rule.metaEventName, 'Lead')}.`
  }
  if (rule.action === 'reveal_form_action') {
    return `El botón de enviar aparece cuando ${triggerCondition}.`
  }
  const actionText = videoActionRuleLabels[rule.action]
  return `Cuando ${triggerCondition}, ${actionText} ${targetLabel}.`
}

const escapeEditorVideoSelectorValue = (value: string) => {
  if (typeof window !== 'undefined' && window.CSS && typeof window.CSS.escape === 'function') {
    return window.CSS.escape(value)
  }
  return value.replace(/["\\#.:,[\]>+~*'=()\s]/g, '\\$&')
}

const findEditorVideoElementInDocument = (doc: Document, blockId: string) => {
  const targetId = String(blockId || '').trim()
  if (!targetId) return null
  const escaped = escapeEditorVideoSelectorValue(targetId)
  const hostSelectors = [
    `[data-rstk-block-id="${escaped}"]`,
    `[data-rstk-edit-id="${escaped}"]`,
    `[data-ristak-edit-id="${escaped}"]`,
    `[data-ristack-edit-id="${escaped}"]`,
    `[data-rstk-video-action-source="${escaped}"]`
  ]

  for (const selector of hostSelectors) {
    const host = doc.querySelector<HTMLElement>(selector)
    if (!host) continue
    if (host.tagName.toLowerCase() === 'video') return host as HTMLVideoElement
    const video = host.querySelector<HTMLVideoElement>('video')
    if (video) return video
  }

  return doc.querySelector<HTMLVideoElement>(`video[data-rstk-video-action-source="${escaped}"], video[data-rstk-edit-id="${escaped}"], video[data-rstk-block-id="${escaped}"]`)
}

const getEditorVideoElement = (blockId: string) => {
  const rootVideo = findEditorVideoElementInDocument(document, blockId)
  if (rootVideo) return rootVideo

  const frames = Array.from(document.querySelectorAll<HTMLIFrameElement>('iframe'))
  for (const frame of frames) {
    try {
      const frameDoc = frame.contentDocument
      if (!frameDoc) continue
      const frameVideo = findEditorVideoElementInDocument(frameDoc, blockId)
      if (frameVideo) return frameVideo
    } catch {
      // Cross-origin embeds are not seekable from the editor.
    }
  }

  return null
}

const getCurrentEditorVideoTime = (blockId: string) => {
  const video = getEditorVideoElement(blockId)
  return clampVideoActionTime(video?.currentTime || 0)
}

const getEditorVideoDuration = (blockId: string) => {
  const video = getEditorVideoElement(blockId)
  const duration = Number(video?.duration)
  return Number.isFinite(duration) && duration > 0 ? clampVideoActionTime(duration) : 0
}

const seekEditorVideoToTime = (blockId: string, timeSeconds: unknown) => {
  const video = getEditorVideoElement(blockId)
  if (!video) return
  const nextTime = clampVideoActionTime(timeSeconds)
  try {
    video.currentTime = nextTime
  } catch {
    return
  }
}

const getVideoActionTimelineMax = (rules: VideoActionRule[], durationSeconds = 0) => {
  const videoDuration = clampVideoActionTime(durationSeconds)
  if (videoDuration > 0) return videoDuration
  const maxRuleTime = rules
    .filter(rule => rule.triggerType === 'timeline_reached')
    .reduce((max, rule) => Math.max(max, rule.triggerValue), 0)
  return Math.max(VIDEO_ACTION_TIMELINE_FALLBACK_SECONDS, maxRuleTime + VIDEO_ACTION_TIMELINE_PADDING_SECONDS)
}

const buildVideoActionHiddenNotes = (blocks: SiteBlock[]) => {
  const blockById = new Map(blocks.map(block => [block.id, block]))
  const notes = new Map<string, string>()

  blocks
    .filter(block => block.blockType === 'video')
    .forEach(videoBlock => {
      const videoLabel = getReadableBlockLabel(videoBlock).toLowerCase().includes('video')
        ? getReadableBlockLabel(videoBlock).toLowerCase()
        : `video ${getReadableBlockLabel(videoBlock).toLowerCase()}`

      getVideoActionRules(videoBlock.settings || {}).forEach(rule => {
        if (!['show', 'open_form'].includes(rule.action) || rule.before !== 'hidden') return
        getVideoActionTargetIds(rule).forEach(targetId => {
          if (!targetId || targetId === POPUP_SURFACE_ID || !blockById.has(targetId)) return
          if (notes.has(targetId)) return
          notes.set(targetId, `Oculto hasta que ${getVideoActionTriggerConditionText(rule, videoLabel)}`)
        })
      })
    })

  return notes
}
const isPopupEditableBlockType = (blockType: SiteBlockType) => !PANEL_BLOCK_TYPES.has(blockType)
const getPopupBlockSettings = (settings: Record<string, unknown> = {}) => ({
  ...settings,
  popupId: POPUP_SURFACE_ID,
  renderLocation: 'popup'
})
const getPopupPaletteBlockTypes = (site: PublicSite) => (
  (isLanding(site) ? landingBlockTypes : formBlockTypes).filter(isPopupEditableBlockType)
)

const getSectionColumns = (block?: SiteBlock | null) => {
  const value = Number(block?.settings?.sectionColumns ?? block?.settings?.columns)
  if (!Number.isFinite(value)) return 1
  return Math.min(3, Math.max(1, Math.round(value)))
}

const getBlockSectionId = (block: SiteBlock) => getSettingString(block.settings || {}, 'sectionId')

const getBlockSectionColumn = (block: SiteBlock) => {
  const value = Number(block.settings?.sectionColumn)
  if (!Number.isFinite(value)) return 0
  return Math.min(2, Math.max(0, Math.round(value)))
}

const getSectionColumnLabel = (columns: number) =>
  columns === 1 ? 'Franja 1 columna' : `Franja ${columns} columnas`

const makeLandingLane = (section: SiteBlock | null, sortOrder: number): LandingSectionLane => {
  const columns = section ? getSectionColumns(section) : 1
  return {
    id: section?.id || '__legacy-section__',
    section,
    columns,
    columnBlocks: Array.from({ length: columns }, () => []),
    sortOrder
  }
}

const buildLandingSectionLanes = (pageBlocks: SiteBlock[]): LandingSectionLane[] => {
  const sortedBlocks = [...pageBlocks].sort((a, b) => a.sortOrder - b.sortOrder)
  const sectionLanes = sortedBlocks
    .filter(isSectionBlock)
    .map(block => makeLandingLane(block, block.sortOrder))
  const sectionById = new Map(sectionLanes.map(lane => [lane.id, lane]))
  let legacyLane: LandingSectionLane | null = null

  const ensureLegacyLane = () => {
    if (!legacyLane) {
      legacyLane = makeLandingLane(null, -1)
      sectionLanes.unshift(legacyLane)
    }
    return legacyLane
  }

  sortedBlocks.forEach(block => {
    if (isSectionBlock(block)) return
    if (isPanelBlock(block)) return

    const explicitSectionId = getBlockSectionId(block)
    const explicitLane = explicitSectionId ? sectionById.get(explicitSectionId) : null
    const previousLane = explicitLane || [...sectionLanes]
      .filter(lane => lane.section && lane.sortOrder <= block.sortOrder)
      .sort((a, b) => b.sortOrder - a.sortOrder)[0]
    const lane = previousLane || ensureLegacyLane()
    const columnIndex = Math.min(lane.columns - 1, getBlockSectionColumn(block))
    lane.columnBlocks[columnIndex].push(block)
  })

  return sectionLanes
    .filter(lane => lane.section || lane.columnBlocks.some(column => column.length > 0))
    .sort((a, b) => a.sortOrder - b.sortOrder)
    .map(lane => ({
      ...lane,
      columnBlocks: lane.columnBlocks.map(column => [...column].sort((a, b) => a.sortOrder - b.sortOrder))
    }))
}

const buildLandingBlockOrderGroups = (
  pageBlocks: SiteBlock[],
  lanes: LandingSectionLane[] = buildLandingSectionLanes(pageBlocks)
): LandingBlockOrderGroup[] => {
  const sortedBlocks = [...pageBlocks].sort((a, b) => a.sortOrder - b.sortOrder)
  const laneBySectionId = new Map(lanes.filter(lane => lane.section).map(lane => [lane.section!.id, lane]))
  const groupedIds = new Set<string>()
  const groups = sortedBlocks
    .filter(isTopLevelLandingBlock)
    .map(anchor => {
      const groupBlocks = [anchor]
      groupedIds.add(anchor.id)

      if (isSectionBlock(anchor)) {
        const lane = laneBySectionId.get(anchor.id)
        const laneChildIds = new Set((lane?.columnBlocks || []).flat().map(block => block.id))
        const sectionChildren = sortedBlocks.filter(block => laneChildIds.has(block.id))
        sectionChildren.forEach(block => groupedIds.add(block.id))
        groupBlocks.push(...sectionChildren)
      }

      return {
        id: anchor.id,
        sortOrder: anchor.sortOrder,
        blocks: groupBlocks
      }
    })

  sortedBlocks
    .filter(block => !groupedIds.has(block.id))
    .forEach(block => {
      groupedIds.add(block.id)
      groups.push({
        id: block.id,
        sortOrder: block.sortOrder,
        blocks: [block]
      })
    })

  return groups.sort((a, b) => a.sortOrder - b.sortOrder)
}

const findNearestRemainingBlockId = (
  beforeBlockIds: string[],
  candidateBlocks: SiteBlock[],
  anchorBlockId: string,
  deletedBlockIds: string[]
) => {
  const candidateIds = new Set(candidateBlocks.map(block => block.id))
  if (!candidateIds.size) return ''

  const deletedIds = new Set(deletedBlockIds)
  const anchorIndex = beforeBlockIds.indexOf(anchorBlockId)
  const startIndex = anchorIndex >= 0 ? anchorIndex : beforeBlockIds.length

  for (let index = startIndex + 1; index < beforeBlockIds.length; index += 1) {
    const id = beforeBlockIds[index]
    if (candidateIds.has(id) && !deletedIds.has(id)) return id
  }

  for (let index = startIndex - 1; index >= 0; index -= 1) {
    const id = beforeBlockIds[index]
    if (candidateIds.has(id) && !deletedIds.has(id)) return id
  }

  return candidateBlocks[0]?.id || ''
}

const getButtonAction = (settings: Record<string, unknown>): ButtonAction => {
  const action = getSettingString(settings, 'buttonAction') as ButtonAction
  return ['url', 'next_page', 'specific_page', 'open_popup', 'close_popup'].includes(action) ? action : 'url'
}

const isFormCompletionAction = (value: unknown): value is FormCompletionAction =>
  value === 'form_default' || value === 'next_page' || value === 'next_page_if_qualified' || value === 'specific_page' || value === 'specific_page_if_qualified' || value === 'redirect' || value === 'redirect_qualified'

const getFormCompletionAction = (settings: Record<string, unknown>): FormCompletionAction => {
  const action = getSettingString(settings, 'completionAction') as FormCompletionAction
  return isFormCompletionAction(action) ? action : 'form_default'
}

