const getCalendarCompletionAction = (settings: Record<string, unknown>): CalendarCompletionAction => {
  const action = getSettingString(settings, 'calendarCompletionAction')
  return action === 'next_page' || action === 'specific_page' || action === 'redirect' ? action : 'calendar_default'
}

const getForwardFunnelPage = (site?: PublicSite | null, activePageId = ''): SitePage | null => {
  const pages = normalizeFunnelPages(site)
  const resolvedPageId = pages.some(page => page.id === activePageId)
    ? activePageId
    : ''
  if (!resolvedPageId) return null
  const index = pages.findIndex(page => page.id === resolvedPageId)
  return index >= 0 ? pages[index + 1] || null : null
}

const shouldDefaultFunnelBlockToNextPage = (site?: PublicSite | null, siteType?: SiteType, activePageId = '') => {
  const resolvedSiteType = site?.siteType || siteType
  return resolvedSiteType === 'landing_page' &&
    Boolean(site) &&
    !isImportedHtmlSite(site) &&
    getSitePageMode(site) === 'funnel' &&
    Boolean(getForwardFunnelPage(site, activePageId))
}

const normalizeOption = (option: string | SiteBlockOption, index: number): SiteBlockOption => {
  if (typeof option === 'string') {
    return {
      id: `option-${index}`,
      label: option,
      value: option,
      action: 'continue'
    }
  }

  const label = option.label || option.value || `Opción ${index + 1}`
  return {
    id: option.id || `option-${index}`,
    label,
    value: option.value || label,
    action: normalizeVisibleRuleAction(option.action),
    targetBlockId: option.targetBlockId || '',
    targetPageId: option.targetPageId || '',
    message: option.message || '',
    redirectUrl: option.redirectUrl || '',
    submitBeforeAction: true,
    tag: option.tag || '',
    category: option.category || '',
    warnBeforeDisqualify: option.warnBeforeDisqualify === true,
    disqualifyNoticeMessage: option.disqualifyNoticeMessage || ''
  }
}

const getOptions = (block: SiteBlock): SiteBlockOption[] =>
  (block.options || []).map(normalizeOption)

const stringifyItems = (settings: Record<string, unknown>) => {
  const items = Array.isArray(settings.items) ? settings.items : []
  return items.map(item => {
    if (item && typeof item === 'object') {
      const record = item as Record<string, unknown>
      return [record.title, record.text, record.author].filter(Boolean).join(' | ')
    }
    return String(item || '')
  }).join('\n')
}

const parseItems = (value: string) => value
  .split('\n')
  .map(line => line.trim())
  .filter(Boolean)
  .map(line => {
    const [title, text, author] = line.split('|').map(part => part.trim())
    return { title, text: text || '', author: author || '' }
  })

interface PanelLink { label: string; url: string; pageId: string }

// Lista cruda de enlaces del panel (sin filtrar). Distingue enlaces a página
// (pageId) de enlaces libres (url). El canvas usa resolvePanelNavLinks para
// filtrar páginas inexistentes; el editor usa esta lista para separar ambos.
const getPanelLinks = (settings: Record<string, unknown>): PanelLink[] => {
  const links = Array.isArray(settings.panelLinks) ? settings.panelLinks : []
  return links
    .map((item): PanelLink => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>
        return {
          label: String(record.label || record.title || record.name || '').trim(),
          url: String(record.url || record.href || '#').trim() || '#',
          pageId: String(record.pageId || record.page_id || '').trim()
        }
      }
      const [label, url] = String(item || '').split('|').map(part => part.trim())
      return { label, url: url || '#', pageId: '' }
    })
    .filter(item => item.label || item.pageId)
}

// Enlaces del panel que NO apuntan a una página (URL/ancla libre). Se editan
// en la caja de "Enlaces personalizados".
const getPanelCustomLinks = (settings: Record<string, unknown>) =>
  getPanelLinks(settings).filter(link => !link.pageId)

const stringifyPanelCustomLinks = (settings: Record<string, unknown>) =>
  getPanelCustomLinks(settings).map(item => `${item.label} | ${item.url}`).join('\n')

const parsePanelCustomLinks = (value: string): PanelLink[] => value
  .split('\n')
  .map(line => line.trim())
  .filter(Boolean)
  .map(line => {
    const [label, url] = line.split('|').map(part => part.trim())
    return { label, url: url || '#', pageId: '' }
  })

interface CanvasItem { title: string; text: string; author: string }

// Mirrors backend getItems/getItemTone/stripToneMarker so canvas lists render
// identically to the published page (incl. +/- pro/con markers).
const getCanvasItems = (settings: Record<string, unknown>): CanvasItem[] => {
  const items = Array.isArray(settings.items) ? settings.items : []
  return items
    .map((item) => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>
        return {
          title: String(record.title || record.label || record.name || ''),
          text: String(record.text || record.content || record.description || ''),
          author: String(record.author || record.role || '')
        }
      }
      return { title: String(item || ''), text: '', author: '' }
    })
    .filter(item => item.title || item.text)
}

const getItemTone = (item: CanvasItem): 'pro' | 'con' | 'neutral' => {
  const raw = String(item.title || item.text || '').trim()
  if (/^[+✓✔]/.test(raw)) return 'pro'
  if (/^[-–—✗✘x×]/i.test(raw)) return 'con'
  return 'neutral'
}

const stripToneMarker = (value: string) => String(value || '').replace(/^\s*[+\-–—✓✔✗✘x×]\s*/i, '').trim()

