const EditablePageTitle: React.FC<{
  pageId: string
  title: string
  inputClassName?: string
  onFocus: () => void
  onRename: (pageId: string, title: string) => void
  onDone: () => void
}> = ({ pageId, title, inputClassName, onFocus, onRename, onDone }) => {
  const [draft, setDraft] = useState(title)
  const inputRef = useRef<HTMLInputElement>(null)
  const cancelRenameRef = useRef(false)

  useEffect(() => setDraft(title), [title])
  useEffect(() => {
    window.setTimeout(() => {
      inputRef.current?.focus()
      inputRef.current?.select()
    }, 0)
  }, [])

  const commit = () => {
    if (cancelRenameRef.current) {
      cancelRenameRef.current = false
      setDraft(title)
      onDone()
      return
    }

    const next = draft.trim() || title
    setDraft(next)
    if (next !== title) onRename(pageId, next)
    onDone()
  }

  return (
    <input
      ref={inputRef}
      className={inputClassName || styles.pageTitleInput}
      value={draft}
      draggable={false}
      aria-label="Nombre de página"
      onFocus={onFocus}
      onPointerDown={(event) => event.stopPropagation()}
      onClick={(event) => event.stopPropagation()}
      onChange={(event) => setDraft(event.target.value)}
      onBlur={commit}
      onKeyDown={(event) => {
        event.stopPropagation()
        if (event.key === 'Enter') {
          event.preventDefault()
          event.currentTarget.blur()
        }
        if (event.key === 'Escape') {
          cancelRenameRef.current = true
          event.currentTarget.blur()
        }
      }}
    />
  )
}

const Palette: React.FC<{
  title?: string
  blockTypes: SiteBlockType[]
  existingBlocks?: SiteBlock[]
  systemScopeBlocks?: SiteBlock[]
  elements?: SiteBlock[]
  selectedElementId?: string
  onAdd: (blockType: SiteBlockType, options?: AddBlockOptions) => void
  onSelectElement?: (blockId: string) => void
  onMoveElement?: (blockId: string, direction: BlockMoveDirection) => void
  onToggleElementVisibility?: (block: SiteBlock) => void
  onDeleteElement?: (block: SiteBlock) => void
  onReorderElements?: (orderedBlocks: SiteBlock[]) => void
  getMoveState?: (block: SiteBlock) => BlockMoveState
  onPaletteDragStart: (payload: PaletteDragPayload, position: PaletteDragPosition | null) => void
  onPaletteDragMove: (position: PaletteDragPosition | null) => void
  onPaletteDragEnd: () => void
}> = ({
  title,
  blockTypes,
  existingBlocks = [],
  systemScopeBlocks,
  elements = [],
  selectedElementId = '',
  onAdd,
  onSelectElement,
  onMoveElement,
  onToggleElementVisibility,
  onDeleteElement,
  onReorderElements,
  getMoveState,
  onPaletteDragStart,
  onPaletteDragMove,
  onPaletteDragEnd
}) => {
  const [viewMode, setViewMode] = useState<PaletteViewMode>('blocks')
  const elementSensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 6 } }))
  const allowed = new Set(blockTypes)
  const existingPanelTypes = new Set(existingBlocks.filter(isPanelBlock).map(block => block.blockType))
  const usedSystemKeys = getUsedSystemFormFieldKeys(systemScopeBlocks || existingBlocks)
  const groups = paletteGroups
    .map(group => ({
      label: group.label,
      items: group.items.filter(item => {
        const preset = getSystemFormFieldPresetForPaletteItem(item)
        return allowed.has(item.blockType) &&
          (!PANEL_BLOCK_TYPES.has(item.blockType) || !existingPanelTypes.has(item.blockType)) &&
          (!preset || !usedSystemKeys.has(preset.key))
      })
    }))
    .filter(group => group.items.length > 0)
  const handleElementDragEnd = (event: DragEndEvent) => {
    if (!event.over || event.active.id === event.over.id) return
    const oldIndex = elements.findIndex(block => block.id === event.active.id)
    const newIndex = elements.findIndex(block => block.id === event.over?.id)
    if (oldIndex < 0 || newIndex < 0) return
    onReorderElements?.(arrayMove(elements, oldIndex, newIndex))
  }

  return (
    <aside className={styles.palette}>
      <div className={styles.panelHeader}>
        <strong>{title || (viewMode === 'elements' ? 'Elementos' : 'Bloques')}</strong>
        <button
          type="button"
          className={styles.paletteHeaderToggle}
          aria-pressed={viewMode === 'elements'}
          aria-label={viewMode === 'elements' ? 'Ver bloques' : 'Ver elementos'}
          onClick={() => setViewMode(viewMode === 'elements' ? 'blocks' : 'elements')}
        >
          {viewMode === 'elements' ? <LayoutTemplate size={13} /> : <ListOrdered size={13} />}
          {viewMode === 'elements' ? 'Ver bloques' : 'Ver elementos'}
        </button>
      </div>

      {viewMode === 'elements' ? (
        elements.length ? (
          <DndContext sensors={elementSensors} collisionDetection={closestCenter} onDragEnd={handleElementDragEnd}>
            <SortableContext items={elements.map(block => block.id)} strategy={verticalListSortingStrategy}>
              <div className={styles.paletteElementList}>
                {elements.map((block, index) => {
                  const moveState = getMoveState?.(block) || {
                    canMoveUp: index > 0,
                    canMoveDown: index < elements.length - 1
                  }
                  return (
                    <PaletteElementItem
                      key={block.id}
                      block={block}
                      selected={selectedElementId === block.id}
                      canMoveUp={moveState.canMoveUp}
                      canMoveDown={moveState.canMoveDown}
                      onSelect={() => onSelectElement?.(block.id)}
                      onMoveUp={() => onMoveElement?.(block.id, 'up')}
                      onMoveDown={() => onMoveElement?.(block.id, 'down')}
                      onToggleVisibility={() => onToggleElementVisibility?.(block)}
                      onDelete={onDeleteElement ? () => onDeleteElement(block) : undefined}
                    />
                  )
                })}
              </div>
            </SortableContext>
          </DndContext>
        ) : (
          <div className={styles.paletteEmpty}>
            <ListOrdered size={18} />
            <p>Agrega un bloque para verlo aquí.</p>
          </div>
        )
      ) : (
        <div className={styles.paletteGroups}>
          {groups.map(group => (
            <div key={group.label} className={styles.paletteGroup}>
              <span className={styles.paletteGroupLabel}>
                <span>{group.label}</span>
                <span className={styles.paletteGroupHint}>(Arrastra)</span>
              </span>
              <div className={styles.paletteItems}>
                {group.items.map(item => (
                  <button
                    key={item.id}
                    type="button"
                    className={styles.paletteItem}
                    draggable
                    onDragStart={(event) => {
                      event.dataTransfer.effectAllowed = 'move'
                      event.dataTransfer.dropEffect = 'move'
                      event.dataTransfer.setData('application/ristak-block', item.blockType)
                      if (item.initialSettings) {
                        event.dataTransfer.setData('application/ristak-block-settings', JSON.stringify(item.initialSettings))
                      }
                      hideNativeDragPreview(event.dataTransfer)
                      const rect = event.currentTarget.getBoundingClientRect()
                      onPaletteDragStart(
                        { blockType: item.blockType, initialSettings: item.initialSettings },
                        event.clientX || event.clientY
                          ? { x: event.clientX, y: event.clientY }
                          : { x: rect.left + rect.width / 2, y: rect.top + rect.height / 2 }
                      )
                    }}
                    onDrag={(event) => {
                      if (event.clientX || event.clientY) {
                        onPaletteDragMove({ x: event.clientX, y: event.clientY })
                      }
                    }}
                    onDragEnd={onPaletteDragEnd}
                    onClick={() => onAdd(item.blockType, { initialSettings: item.initialSettings })}
                  >
                    <span className={styles.paletteIcon}>
                      {item.blockType === SECTION_BLOCK_TYPE ? (
                        <span
                          className={styles.sectionPalettePreview}
                          style={{ gridTemplateColumns: `repeat(${getSettingNumber(item.initialSettings || {}, 'sectionColumns', 1, 1, 3)}, minmax(0, 1fr))` }}
                          aria-hidden="true"
                        >
                          {Array.from({ length: getSettingNumber(item.initialSettings || {}, 'sectionColumns', 1, 1, 3) }).map((_, index) => (
                            <span key={index} />
                          ))}
                        </span>
                      ) : blockIcons[item.blockType]}
                    </span>
                    <span>{item.label}</span>
                    <GripVertical className={styles.paletteGrip} size={14} />
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </aside>
  )
}

const PaletteElementItem: React.FC<{
  block: SiteBlock
  selected: boolean
  canMoveUp: boolean
  canMoveDown: boolean
  onSelect: () => void
  onMoveUp: () => void
  onMoveDown: () => void
  onToggleVisibility: () => void
  onDelete?: () => void
}> = ({ block, selected, canMoveUp, canMoveDown, onSelect, onMoveUp, onMoveDown, onToggleVisibility, onDelete }) => {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: block.id,
    animateLayoutChanges: sortableAnimateLayoutChanges,
    transition: sortableTransition
  })
  const rowStyle: React.CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.52 : undefined,
    zIndex: isDragging ? 5 : undefined
  }
  const name = getElementPanelName(block)
  const hidden = isBlockHidden(block)

  return (
    <div
      ref={setNodeRef}
      className={`${styles.paletteElementRow} ${selected ? styles.paletteElementRowActive : ''} ${hidden ? styles.paletteElementRowHidden : ''}`}
      data-depth={getElementPanelDepth(block)}
      style={rowStyle}
    >
      <span
        className={styles.paletteElementHandle}
        {...attributes}
        {...listeners}
        aria-label={`Arrastrar ${name}`}
        title="Arrastra para ordenar"
      >
        <GripVertical size={14} />
      </span>
      <button type="button" className={styles.paletteElementButton} onClick={onSelect}>
        <span className={styles.paletteIcon}>{blockIcons[block.blockType] || <LayoutTemplate size={15} />}</span>
        <span className={styles.paletteElementText}>
          <span className={styles.paletteElementName}>{name}</span>
          <span className={styles.paletteElementDetail}>{getElementPanelDetail(block)}</span>
        </span>
      </button>
      <span className={styles.paletteElementActions}>
        <button
          type="button"
          className={hidden ? styles.paletteElementVisibilityOff : ''}
          onClick={onToggleVisibility}
          aria-pressed={!hidden}
          aria-label={hidden ? `Mostrar ${name}` : `Ocultar ${name}`}
          title={hidden ? 'Mostrar elemento' : 'Ocultar elemento'}
        >
          {hidden ? <EyeOff size={13} /> : <Eye size={13} />}
        </button>
        <button type="button" disabled={!canMoveUp} onClick={onMoveUp} aria-label={`Subir ${name}`} title="Subir">
          <ArrowUp size={13} />
        </button>
        <button type="button" disabled={!canMoveDown} onClick={onMoveDown} aria-label={`Bajar ${name}`} title="Bajar">
          <ArrowDown size={13} />
        </button>
        {onDelete && (
          <button
            type="button"
            className={styles.paletteElementDelete}
            onClick={onDelete}
            aria-label={`Eliminar ${name}`}
            title="Eliminar elemento"
          >
            <Trash2 size={13} />
          </button>
        )}
      </span>
    </div>
  )
}

// Inline, in-place text editing that renders as the real rstk element, so the
// typography/gradients/spacing match the published page exactly. Content is set
// imperatively to avoid React rewriting the DOM mid-edit (which jumps the caret).
const inlineEditableInvisibleTextPattern = /[\u200B-\u200D\uFEFF]/g

const normalizeInlineEditableText = (value: string, multiline: boolean) => {
  const plainText = String(value || '')
    .replace(inlineEditableInvisibleTextPattern, '')
    .replace(/\u00a0/g, ' ')

  return multiline
    ? plainText.replace(/\r\n?/g, '\n')
    : plainText.replace(/[\r\n]+/g, ' ')
}

const hasInlineEditableText = (value: string) => normalizeInlineEditableText(value, true).trim().length > 0

const readInlineEditableText = (
  element: HTMLElement,
  multiline: boolean,
  placeholder = '',
  currentValue = ''
) => {
  const rawText = multiline ? element.innerText : element.textContent || ''
  const nextText = normalizeInlineEditableText(rawText, multiline)
  const placeholderText = normalizeInlineEditableText(placeholder, multiline).trim()

  if (
    placeholderText &&
    !hasInlineEditableText(currentValue) &&
    element.getAttribute('data-empty') === 'true' &&
    nextText.trim() === placeholderText
  ) {
    return ''
  }

  return hasInlineEditableText(nextText) ? nextText : ''
}

const syncInlineEditableEmptyState = (element: HTMLElement, value: string) => {
  const isEmpty = !hasInlineEditableText(value)
  if (isEmpty && element.textContent) element.textContent = ''
  element.setAttribute('data-empty', isEmpty ? 'true' : 'false')
}

interface InlineEditableProps {
  as?: 'h1' | 'h2' | 'p' | 'span' | 'div' | 'a' | 'strong'
  className?: string
  value: string
  placeholder?: string
  /** Paridad content #4: el publicado imprime este fallback como contenido real
      (label del bloque, 'Continuar', 'Tu marca'...), así que el canvas lo pinta
      a opacidad completa en vez del placeholder tenue. */
  placeholderAsContent?: boolean
  disabled?: boolean
  multiline?: boolean
  onChange: (value: string) => void
  onCommit?: () => void
}

const InlineEditable: React.FC<InlineEditableProps> = ({
  as = 'div', className, value, placeholder, placeholderAsContent, disabled, multiline, onChange, onCommit
}) => {
  const ref = useRef<HTMLElement>(null)
  const editingRef = useRef(false)

  useEffect(() => {
    const el = ref.current
    if (editingRef.current) return
    if (el && el.textContent !== value) el.textContent = value
    if (el) syncInlineEditableEmptyState(el, value)
  }, [value])

  const Tag = as as React.ElementType
  const handleEditableChange = (element: HTMLElement) => {
    const text = readInlineEditableText(element, Boolean(multiline), placeholder, value)
    syncInlineEditableEmptyState(element, text)
    onChange(text)
    return text
  }

  return (
    <Tag
      ref={ref}
      className={className}
      contentEditable={disabled ? false : 'plaintext-only'}
      suppressContentEditableWarning
      spellCheck={false}
      role="textbox"
      data-rstk-edit=""
      data-empty={hasInlineEditableText(value) ? 'false' : 'true'}
      data-placeholder={placeholder || ''}
      data-placeholder-live={placeholderAsContent ? 'true' : undefined}
      onFocus={(event: React.FocusEvent<HTMLElement>) => {
        editingRef.current = true
        syncInlineEditableEmptyState(event.currentTarget, readInlineEditableText(event.currentTarget, Boolean(multiline), placeholder, value))
      }}
      onInput={(event: React.FormEvent<HTMLElement>) => {
        handleEditableChange(event.currentTarget)
      }}
      onPaste={(event: React.ClipboardEvent<HTMLElement>) => {
        event.preventDefault()
        const pasteText = normalizeInlineEditableText(event.clipboardData.getData('text/plain'), Boolean(multiline))
        if (!pasteText) return

        const selection = event.currentTarget.ownerDocument.getSelection()
        if (!selection?.rangeCount) return

        const range = selection.getRangeAt(0)
        range.deleteContents()
        const textNode = event.currentTarget.ownerDocument.createTextNode(pasteText)
        range.insertNode(textNode)
        range.setStartAfter(textNode)
        range.collapse(true)
        selection.removeAllRanges()
        selection.addRange(range)
        handleEditableChange(event.currentTarget)
      }}
      onBlur={(event: React.FocusEvent<HTMLElement>) => {
        editingRef.current = false
        const text = readInlineEditableText(event.currentTarget, Boolean(multiline), placeholder, value)
        syncInlineEditableEmptyState(event.currentTarget, text)
        if (text !== value) onChange(text)
        onCommit?.()
      }}
      onKeyDown={(event: React.KeyboardEvent<HTMLElement>) => {
        if (!multiline && event.key === 'Enter') {
          event.preventDefault()
          event.currentTarget.blur()
        }
      }}
    />
  )
}

const InlineButtonEditable: React.FC<Omit<InlineEditableProps, 'as' | 'className'> & {
  subtitle?: string
  onSubtitleChange?: (value: string) => void
  settings?: Record<string, unknown>
}> = ({ subtitle = '', onSubtitleChange, disabled, onCommit, settings, ...props }) => {
  const iconName = normalizeButtonIconName(settings?.buttonIcon)
  const iconSide = normalizeButtonIconSide(settings?.buttonIconSide)
  const icon = iconName ? <span className="rstk-button-icon" aria-hidden="true"><ButtonIconGlyph name={iconName} /></span> : null

  if (!iconName) {
    return (
      <a className="rstk-button-link" href="#" onClick={(event) => event.preventDefault()}>
        <InlineEditable {...props} disabled={disabled} onCommit={onCommit} as="span" className="rstk-button-label" />
        {subtitle || onSubtitleChange ? (
          <InlineEditable
            as="span"
            className="rstk-button-subtitle"
            value={subtitle}
            placeholder="Subtexto"
            disabled={disabled}
            onChange={(value) => onSubtitleChange?.(value)}
            onCommit={onCommit}
          />
        ) : null}
      </a>
    )
  }

  return (
    <a className="rstk-button-link" href="#" onClick={(event) => event.preventDefault()}>
      <span className={`rstk-button-content rstk-button-icon-${iconSide}`}>
        {iconSide === 'left' ? icon : null}
        <span className="rstk-button-text-stack">
          <InlineEditable {...props} disabled={disabled} onCommit={onCommit} as="span" className="rstk-button-label" />
          {subtitle || onSubtitleChange ? (
            <InlineEditable
              as="span"
              className="rstk-button-subtitle"
              value={subtitle}
              placeholder="Subtexto"
              disabled={disabled}
              onChange={(value) => onSubtitleChange?.(value)}
              onCommit={onCommit}
            />
          ) : null}
        </span>
        {iconSide === 'right' ? icon : null}
      </span>
    </a>
  )
}

// Renders the canvas at the available editor width. Avoid transform-scaling the
// whole page: browser compositing makes text/buttons look like a raster image.
interface CanvasStageProps {
  designWidth: number
  canvasClassName: string
  canvasStyle: React.CSSProperties
  active?: boolean
  pageSelected?: boolean
  fluidAboveDesign?: boolean
  onClear?: () => void
  onDragOver?: React.DragEventHandler<HTMLDivElement>
  onDragLeave?: React.DragEventHandler<HTMLDivElement>
  onDrop?: React.DragEventHandler<HTMLDivElement>
  overlay?: React.ReactNode
  children: React.ReactNode
}

const CanvasStage: React.FC<CanvasStageProps> = ({
  designWidth, canvasClassName, canvasStyle, active, pageSelected, fluidAboveDesign, onClear, onDragOver, onDragLeave, onDrop, overlay, children
}) => {
  const viewportRef = useRef<HTMLDivElement>(null)
  const stageRef = useRef<HTMLDivElement>(null)
  const [scale, setScale] = useState(1)
  const [renderWidth, setRenderWidth] = useState(designWidth)
  const [stageHeight, setStageHeight] = useState(0)

  useLayoutEffect(() => {
    const viewport = viewportRef.current
    const stage = stageRef.current
    if (!viewport || !stage) return
    const recompute = () => {
      const avail = Math.max(1, viewport.clientWidth - (fluidAboveDesign ? 0 : 8))
      const nextRenderWidth = fluidAboveDesign && avail > designWidth ? avail : Math.min(designWidth, avail)
      setRenderWidth(nextRenderWidth)
      setScale(1)
      setStageHeight(stage.offsetHeight)
    }
    recompute()
    const observer = new ResizeObserver(recompute)
    observer.observe(viewport)
    observer.observe(stage)
    return () => observer.disconnect()
  }, [designWidth, fluidAboveDesign])

  return (
    <div
      ref={viewportRef}
      className={`canvasViewport ${fluidAboveDesign ? 'canvasViewportFlush' : ''} ${active ? 'canvasViewportActive' : ''}`}
      style={canvasStyle}
      onClick={onClear}
      onDragOver={onDragOver}
      onDragLeave={onDragLeave}
      onDrop={onDrop}
    >
      <div
        className="canvasScaler"
        style={{ ...canvasStyle, width: Math.round(renderWidth), height: Math.round(stageHeight) } as React.CSSProperties}
      >
        <div
          ref={stageRef}
          className={`canvasStage ${canvasClassName} ${pageSelected ? 'canvasPageSelected' : ''}`}
          style={{ ...canvasStyle, width: renderWidth, ['--rstk-scale' as string]: scale } as React.CSSProperties}
        >
          {children}
        </div>
      </div>
      {overlay}
    </div>
  )
}

interface SortableCanvasBlockProps {
  block: SiteBlock
  blocks: SiteBlock[]
  index: number
  selected: boolean
  videoActionHoverTargetId?: string
  videoActionHiddenNotes?: Map<string, string>
  showVideoFormGatePreview?: boolean
  site: PublicSite
  forms: PublicSite[]
  calendars: CalendarType[]
  pages: SitePage[]
  activePageId: string
  canMoveUp: boolean
  canMoveDown: boolean
  embeddedFormEditor?: EmbeddedFormCanvasEditorBridge | null
  onSelect: () => void
  onDelete: () => void
  onDuplicate: () => void
  onMoveUp: () => void
  onMoveDown: () => void
  onClearSelection: () => void
  onPatchBlock: (patch: Partial<SiteBlock>) => void
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}

const sortableTransition = {
  duration: 520,
  easing: 'cubic-bezier(0.2, 0.8, 0.2, 1)'
}

const sortableAnimateLayoutChanges: AnimateLayoutChanges = (args) => {
  if (args.isSorting || args.wasDragging) {
    return defaultAnimateLayoutChanges(args)
  }

  return false
}

const SortableCanvasBlock: React.FC<SortableCanvasBlockProps> = ({
  block,
  blocks,
  index,
  selected,
  videoActionHoverTargetId = '',
  videoActionHiddenNotes,
  showVideoFormGatePreview = false,
  site,
  forms,
  calendars,
  pages,
  activePageId,
  canMoveUp,
  canMoveDown,
  embeddedFormEditor,
  onSelect,
  onDelete,
  onDuplicate,
  onMoveUp,
  onMoveDown,
  onClearSelection,
  onPatchBlock,
  onPatchSettings,
  onSave
}) => {
  const videoActionHiddenNote = videoActionHiddenNotes?.get(block.id) || ''
  const toolbarPositionClass = canMoveDown ? '' : 'rstkBlockToolsAbove'
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: block.id,
    animateLayoutChanges: sortableAnimateLayoutChanges,
    transition: sortableTransition
  })
  const handleClick = (event: React.MouseEvent<HTMLDivElement>) => {
    const targetElement = event.target instanceof Element ? event.target : null
    const clickedBlockTools = Boolean(targetElement?.closest('.rstkBlockTools'))

    if (!clickedBlockTools) {
      const selectionSurface = event.currentTarget.querySelector<HTMLElement>(BLOCK_SELECTION_SURFACE_SELECTOR)

      if (selectionSurface && !clickHitsSelectionSurface(selectionSurface, event)) {
        event.stopPropagation()
        onClearSelection()
        return
      }
    }

    event.stopPropagation()
    onSelect()
  }

  return (
	    <div
	      ref={setNodeRef}
	      data-rstk-block-id={block.id}
	      data-rstk-block-index={index}
	      data-rstk-page-block={isPanelBlock(block) ? 'true' : undefined}
	      style={{
        transform: CSS.Transform.toString(transform),
	        transition: transition || 'transform 520ms cubic-bezier(0.2, 0.8, 0.2, 1)',
        opacity: isDragging ? 0.34 : undefined,
        zIndex: isDragging ? 8 : undefined,
        ...getBlockCanvasStyle(block, { site, parentBlock: getParentSectionBlock(block, blocks) })
      }}
      className={getBlockStyleClassName(block, `rstkSel ${surfaceSelectionBlockTypes.has(block.blockType) ? 'rstkSurfaceSelectionHost' : ''} ${selected ? 'rstkSelActive' : ''} ${toolbarPositionClass} ${isDragging ? 'rstkSelDragging' : ''} ${videoActionHoverTargetId === block.id ? 'rstkVideoActionHover' : ''} ${videoActionHiddenNote ? 'rstkVideoActionGhost' : ''}`)}
      onClick={handleClick}
    >
      {videoActionHiddenNote && <span className="rstkVideoActionNote">{videoActionHiddenNote}</span>}
      <BlockBackgroundVideo block={block} />
      <div className="rstkBlockTools">
        <button type="button" className="rstkBlockTool rstkBlockToolDrag" {...attributes} {...listeners} aria-label="Reordenar bloque">
          <GripVertical size={15} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          disabled={!canMoveUp}
          onClick={(event) => { event.stopPropagation(); onMoveUp() }}
          aria-label="Subir bloque"
        >
          <ArrowUp size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          disabled={!canMoveDown}
          onClick={(event) => { event.stopPropagation(); onMoveDown() }}
          aria-label="Bajar bloque"
        >
          <ArrowDown size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          onClick={(event) => { event.stopPropagation(); onDuplicate() }}
          onPointerDown={(event) => event.stopPropagation()}
          aria-label="Duplicar bloque"
          title="Duplicar"
        >
          <Copy size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool rstkBlockToolDelete"
          onClick={(event) => { event.stopPropagation(); onDelete() }}
          onPointerDown={(event) => event.stopPropagation()}
          aria-label="Eliminar bloque"
          title="Eliminar"
        >
          <Trash2 size={14} />
        </button>
      </div>
      <CanvasPreviewBlock
        block={block}
        site={site}
        blocks={blocks}
        forms={forms}
        calendars={calendars}
        pages={pages}
        activePageId={activePageId}
        selected={selected}
        showVideoFormGatePreview={showVideoFormGatePreview}
        embeddedFormEditor={embeddedFormEditor?.parentBlockId === block.id ? embeddedFormEditor : undefined}
        onPatchBlock={onPatchBlock}
        onPatchSettings={onPatchSettings}
        onSave={onSave}
      />
    </div>
  )
}

interface PopupCanvasSurfaceProps {
  site: PublicSite
  blocks: SiteBlock[]
  lanes: LandingSectionLane[]
  selectedBlockId: string
  forms: PublicSite[]
  calendars: CalendarType[]
  pages: SitePage[]
  activePageId: string
  selected: boolean
  videoActionHoverTargetId?: string
  videoActionHiddenNotes?: Map<string, string>
  videoFormGatePreviewBlockId?: string
  palettePreviewBlock: SiteBlock | null
  paletteInsertIndex: number | null
  paletteSectionTarget: PaletteSectionTarget | null
  paletteDragging: boolean
  embeddedFormEditor?: EmbeddedFormCanvasEditorBridge | null
  onSelectPopup: () => void
  onClosePopup: () => void
  onSelectBlock: (blockId: string) => void
  onDeleteBlock: (blockId: string) => void
  onDuplicateBlock: (blockId: string) => void
  onMoveBlock: (blockId: string, direction: BlockMoveDirection) => void
  getBlockMoveState: (block: SiteBlock) => BlockMoveState
  onPatchBlock: (blockId: string, patch: Partial<SiteBlock>) => void
  onPatchBlockSettings: (block: SiteBlock, patch: Record<string, unknown>) => void
  onSaveBlock: (blockId: string) => void
}

const PopupCanvasSurface: React.FC<PopupCanvasSurfaceProps> = ({
  site,
  blocks,
  lanes,
  selectedBlockId,
  forms,
  calendars,
  pages,
  activePageId,
  selected,
  videoActionHoverTargetId = '',
  videoActionHiddenNotes,
  videoFormGatePreviewBlockId = '',
  palettePreviewBlock,
  paletteInsertIndex,
  paletteSectionTarget,
  paletteDragging,
  embeddedFormEditor,
  onSelectPopup,
  onClosePopup,
  onSelectBlock,
  onDeleteBlock,
  onDuplicateBlock,
  onMoveBlock,
  getBlockMoveState,
  onPatchBlock,
  onPatchBlockSettings,
  onSaveBlock
}) => {
  const theme = site.theme || {}
  const closeDisplay = normalizePopupCloseDisplay(theme.popupCloseDisplay)
  const closeIcon = getPopupCloseIconText(theme.popupCloseIcon)
  const closeText = getThemeString(theme, 'popupCloseText') || 'Cerrar'
  const showCloseIcon = closeDisplay !== 'text' && closeIcon
  const showCloseText = closeDisplay !== 'icon'
  // Paridad embeds #12: MISMO DOM (.rstk-site-popup*) y MISMAS variables
  // --rstk-popup-* del contrato compartido que el publicado; el shell lo pinta
  // la hoja RSTK_POPUP_CSS inyectada (canvasSiteCss), no CSS copiado a mano.
  // siteIsDark del contrato (igual que renderSitePopup en vivo).
  const popupVars = useMemo(() => ({
    ...buildPopupSurfaceVars(
      (theme || {}) as Record<string, unknown>,
      computeSitePageRenderState(site as unknown as SiteLike).siteIsDark
    )
  }) as React.CSSProperties, [site, theme])
  // Paridad embeds #13: sin bloques, el contenido legacy del theme se pinta con
  // el mismo DOM que el publicado (h2 / p / .rstk-site-popup__action).
  const legacyTitle = getThemeString(theme, 'popupTitle')
  const legacyBody = getThemeString(theme, 'popupBody')
  const legacyButtonText = getThemeString(theme, 'popupButtonText')
  const legacyButtonUrl = safeAbsoluteUrl(theme.popupButtonUrl)
  const hasLegacyContent = Boolean(legacyTitle || legacyBody || legacyButtonText || legacyButtonUrl)

  return (
    <div
      className="rstk-site-popup rstkPopupEditorLayer"
      style={popupVars}
      onClick={(event) => {
        event.stopPropagation()
        onSelectPopup()
      }}
    >
      <section
        className={`rstk-site-popup__box rstkPopupEditorModal ${selected ? 'rstkPopupEditorModalSelected' : ''}`}
        data-rstk-popup-surface="true"
        role="dialog"
        aria-modal="true"
        aria-label="Pop up editable"
        onClick={(event) => {
          event.stopPropagation()
          onSelectPopup()
        }}
      >
        <button
          type="button"
          className="rstk-site-popup__close rstkPopupEditorClose"
          onClick={(event) => {
            event.stopPropagation()
            onClosePopup()
          }}
          aria-label="Cerrar"
        >
          {showCloseIcon && <span aria-hidden="true">{closeIcon}</span>}
          {showCloseText && <strong>{closeText}</strong>}
        </button>
        <div className="rstk-site-popup__content rstkPopupEditorContent">
          {blocks.length === 0 ? (
            palettePreviewBlock && isTopLevelLandingBlockType(palettePreviewBlock.blockType) ? (
              <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
            ) : hasLegacyContent ? (
              <>
                {legacyTitle ? <h2>{legacyTitle}</h2> : null}
                {legacyBody ? (
                  <p>
                    {legacyBody.split('\n').map((line, index) => (
                      <React.Fragment key={index}>
                        {index > 0 && <br />}
                        {line}
                      </React.Fragment>
                    ))}
                  </p>
                ) : null}
                {legacyButtonText || legacyButtonUrl ? (
                  legacyButtonUrl ? (
                    <a className="rstk-site-popup__action" href={legacyButtonUrl} onClick={(event) => event.preventDefault()}>
                      {legacyButtonText || 'Abrir'}
                    </a>
                  ) : (
                    <button type="button" className="rstk-site-popup__action">
                      {legacyButtonText || 'Cerrar'}
                    </button>
                  )
                ) : null}
              </>
            ) : (
              <div className="rstkDropEmpty rstkPopupDropEmpty">
                <Plus size={22} />
                <p>Arrastra primero una franja de 1, 2 o 3 columnas.</p>
              </div>
            )
          ) : (
            <LandingCanvasSections
              lanes={lanes}
              blocks={blocks}
              selectedBlockId={selectedBlockId}
              site={site}
              forms={forms}
              calendars={calendars}
              pages={pages}
              activePageId={activePageId}
              videoActionHoverTargetId={videoActionHoverTargetId}
              videoActionHiddenNotes={videoActionHiddenNotes}
              videoFormGatePreviewBlockId={videoFormGatePreviewBlockId}
              palettePreviewBlock={palettePreviewBlock}
              paletteInsertIndex={paletteInsertIndex}
              paletteSectionTarget={paletteSectionTarget}
              paletteDragging={paletteDragging}
              embeddedFormEditor={embeddedFormEditor}
              onSelectBlock={onSelectBlock}
              onDeleteBlock={onDeleteBlock}
              onDuplicateBlock={onDuplicateBlock}
              onMoveBlock={onMoveBlock}
              getBlockMoveState={getBlockMoveState}
              onPatchBlock={onPatchBlock}
              onPatchBlockSettings={onPatchBlockSettings}
              onSaveBlock={onSaveBlock}
            />
          )}
        </div>
      </section>
    </div>
  )
}

interface LandingCanvasSectionsProps {
  lanes: LandingSectionLane[]
  blocks: SiteBlock[]
  selectedBlockId: string
  site: PublicSite
  forms: PublicSite[]
  calendars: CalendarType[]
  pages: SitePage[]
  activePageId: string
  videoActionHoverTargetId?: string
  videoActionHiddenNotes?: Map<string, string>
  videoFormGatePreviewBlockId?: string
  palettePreviewBlock: SiteBlock | null
  paletteInsertIndex: number | null
  paletteSectionTarget: PaletteSectionTarget | null
  paletteDragging: boolean
  embeddedFormEditor?: EmbeddedFormCanvasEditorBridge | null
  onSelectBlock: (blockId: string) => void
  onDeleteBlock: (blockId: string) => void
  onDuplicateBlock: (blockId: string) => void
  onMoveBlock: (blockId: string, direction: BlockMoveDirection) => void
  getBlockMoveState: (block: SiteBlock) => BlockMoveState
  onPatchBlock: (blockId: string, patch: Partial<SiteBlock>) => void
  onPatchBlockSettings: (block: SiteBlock, patch: Record<string, unknown>) => void
  onSaveBlock: (blockId: string) => void
}

const LandingCanvasSections: React.FC<LandingCanvasSectionsProps> = ({
  lanes,
  blocks,
  selectedBlockId,
  site,
  forms,
  calendars,
  pages,
  activePageId,
  videoActionHoverTargetId = '',
  videoActionHiddenNotes,
  videoFormGatePreviewBlockId = '',
  palettePreviewBlock,
  paletteInsertIndex,
  paletteSectionTarget,
  paletteDragging,
  embeddedFormEditor,
  onSelectBlock,
  onDeleteBlock,
  onDuplicateBlock,
  onMoveBlock,
  getBlockMoveState,
  onPatchBlock,
  onPatchBlockSettings,
  onSaveBlock
}) => {
  const blockIndexById = new Map(blocks.map((block, index) => [block.id, index]))
  const laneBySectionId = new Map(lanes.filter(lane => lane.section).map(lane => [lane.section!.id, lane]))
  const legacyLane = lanes.find(lane => !lane.section)
  const showTopLevelPreview = Boolean(palettePreviewBlock && isTopLevelLandingBlockType(palettePreviewBlock.blockType))
  let legacyRendered = false

  return (
    <>
      {blocks.map((block) => {
        const blockInsertIndex = blockIndexById.get(block.id) ?? 0
        const topLevelPreviewBefore = showTopLevelPreview && paletteInsertIndex === blockInsertIndex

        if (isPanelBlock(block)) {
          const moveState = getBlockMoveState(block)
          return (
            <React.Fragment key={block.id}>
              {topLevelPreviewBefore && palettePreviewBlock && (
                <PaletteInsertPreview block={palettePreviewBlock} forms={forms} calendars={calendars} />
              )}
              <SortableCanvasBlock
                block={block}
                blocks={blocks}
                index={blockInsertIndex}
                selected={selectedBlockId === block.id}
                site={site}
                forms={forms}
                calendars={calendars}
                pages={pages}
                activePageId={activePageId}
                videoActionHoverTargetId={videoActionHoverTargetId}
                videoActionHiddenNotes={videoActionHiddenNotes}
                showVideoFormGatePreview={videoFormGatePreviewBlockId === block.id}
                canMoveUp={moveState.canMoveUp}
                canMoveDown={moveState.canMoveDown}
                embeddedFormEditor={embeddedFormEditor}
                onSelect={() => onSelectBlock(block.id)}
                onDelete={() => onDeleteBlock(block.id)}
                onDuplicate={() => onDuplicateBlock(block.id)}
                onMoveUp={() => onMoveBlock(block.id, 'up')}
                onMoveDown={() => onMoveBlock(block.id, 'down')}
                onClearSelection={() => onSelectBlock('')}
                onPatchBlock={(patch) => onPatchBlock(block.id, patch)}
                onPatchSettings={(patch) => onPatchBlockSettings(block, patch)}
                onSave={() => onSaveBlock(block.id)}
              />
            </React.Fragment>
          )
        }

        if (!isSectionBlock(block)) {
          if (!legacyLane || legacyRendered || getBlockSectionId(block)) return null
          legacyRendered = true
          return (
            <LegacyLandingSection
              key={legacyLane.id}
              lane={legacyLane}
              blocks={blocks}
              blockIndexById={blockIndexById}
              selectedBlockId={selectedBlockId}
              site={site}
              forms={forms}
              calendars={calendars}
	              pages={pages}
	              activePageId={activePageId}
                videoActionHoverTargetId={videoActionHoverTargetId}
                videoActionHiddenNotes={videoActionHiddenNotes}
                videoFormGatePreviewBlockId={videoFormGatePreviewBlockId}
	              palettePreviewBlock={palettePreviewBlock}
	              paletteInsertIndex={paletteInsertIndex}
	              paletteSectionTarget={paletteSectionTarget}
                embeddedFormEditor={embeddedFormEditor}
	              onSelectBlock={onSelectBlock}
              onDeleteBlock={onDeleteBlock}
              onDuplicateBlock={onDuplicateBlock}
              onMoveBlock={onMoveBlock}
              getBlockMoveState={getBlockMoveState}
              onPatchBlock={onPatchBlock}
              onPatchBlockSettings={onPatchBlockSettings}
              onSaveBlock={onSaveBlock}
            />
          )
        }

	        const lane = laneBySectionId.get(block.id)
	        if (!lane) return null
	        return (
	          <React.Fragment key={lane.id}>
	            {topLevelPreviewBefore && palettePreviewBlock && (
	              <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
	            )}
	            <SortableLandingSection
	              lane={lane}
              blocks={blocks}
              blockIndexById={blockIndexById}
              selectedBlockId={selectedBlockId}
              site={site}
              forms={forms}
              calendars={calendars}
              pages={pages}
              activePageId={activePageId}
              videoActionHoverTargetId={videoActionHoverTargetId}
              videoActionHiddenNotes={videoActionHiddenNotes}
              videoFormGatePreviewBlockId={videoFormGatePreviewBlockId}
	              paletteDragging={paletteDragging}
	              palettePreviewBlock={palettePreviewBlock}
	              paletteInsertIndex={paletteInsertIndex}
	              paletteSectionTarget={paletteSectionTarget}
                embeddedFormEditor={embeddedFormEditor}
	              onSelectBlock={onSelectBlock}
              onDeleteBlock={onDeleteBlock}
              onDuplicateBlock={onDuplicateBlock}
              onMoveBlock={onMoveBlock}
              getBlockMoveState={getBlockMoveState}
              onPatchBlock={onPatchBlock}
              onPatchBlockSettings={onPatchBlockSettings}
              onSaveBlock={onSaveBlock}
            />
	          </React.Fragment>
	        )
	      })}
	      {showTopLevelPreview && palettePreviewBlock && paletteInsertIndex !== null && paletteInsertIndex >= blocks.length && (
            <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
	      )}
	      {legacyLane && !legacyRendered && (
	        <LegacyLandingSection
          lane={legacyLane}
          blocks={blocks}
          blockIndexById={blockIndexById}
          selectedBlockId={selectedBlockId}
          site={site}
          forms={forms}
          calendars={calendars}
	          pages={pages}
	          activePageId={activePageId}
          videoActionHoverTargetId={videoActionHoverTargetId}
          videoActionHiddenNotes={videoActionHiddenNotes}
          videoFormGatePreviewBlockId={videoFormGatePreviewBlockId}
	          palettePreviewBlock={palettePreviewBlock}
	          paletteInsertIndex={paletteInsertIndex}
	          paletteSectionTarget={paletteSectionTarget}
          embeddedFormEditor={embeddedFormEditor}
	          onSelectBlock={onSelectBlock}
          onDeleteBlock={onDeleteBlock}
          onDuplicateBlock={onDuplicateBlock}
          onMoveBlock={onMoveBlock}
          getBlockMoveState={getBlockMoveState}
          onPatchBlock={onPatchBlock}
          onPatchBlockSettings={onPatchBlockSettings}
          onSaveBlock={onSaveBlock}
        />
      )}
    </>
  )
}

interface LandingSectionRenderProps {
  lane: LandingSectionLane
  blocks: SiteBlock[]
  blockIndexById: Map<string, number>
  selectedBlockId: string
  site: PublicSite
  forms: PublicSite[]
  calendars: CalendarType[]
  pages: SitePage[]
  activePageId: string
  videoActionHoverTargetId?: string
  videoActionHiddenNotes?: Map<string, string>
  videoFormGatePreviewBlockId?: string
  paletteDragging?: boolean
  palettePreviewBlock?: SiteBlock | null
  paletteInsertIndex?: number | null
  paletteSectionTarget?: PaletteSectionTarget | null
  embeddedFormEditor?: EmbeddedFormCanvasEditorBridge | null
  onSelectBlock: (blockId: string) => void
  onDeleteBlock: (blockId: string) => void
  onDuplicateBlock: (blockId: string) => void
  onMoveBlock: (blockId: string, direction: BlockMoveDirection) => void
  getBlockMoveState: (block: SiteBlock) => BlockMoveState
  onPatchBlock: (blockId: string, patch: Partial<SiteBlock>) => void
  onPatchBlockSettings: (block: SiteBlock, patch: Record<string, unknown>) => void
  onSaveBlock: (blockId: string) => void
}

const LandingSectionColumns: React.FC<LandingSectionRenderProps> = ({
  lane,
  blocks,
  blockIndexById,
  selectedBlockId,
  site,
  forms,
  calendars,
  pages,
  activePageId,
  videoActionHoverTargetId = '',
  videoActionHiddenNotes,
  videoFormGatePreviewBlockId = '',
  paletteDragging,
  palettePreviewBlock,
  paletteInsertIndex,
  paletteSectionTarget,
  embeddedFormEditor,
  onSelectBlock,
  onDeleteBlock,
  onDuplicateBlock,
  onMoveBlock,
  getBlockMoveState,
  onPatchBlock,
  onPatchBlockSettings,
  onSaveBlock
}) => {
  const showContentPreview = Boolean(
    palettePreviewBlock
    && !isTopLevelLandingBlockType(palettePreviewBlock.blockType)
    && typeof paletteInsertIndex === 'number'
    && paletteSectionTarget
    && lane.section
    && paletteSectionTarget.sectionId === lane.section.id
  )

  return (
    <div className="rstk-section-columns">
      {lane.columnBlocks.map((columnBlocks, columnIndex) => {
        const isTargetColumn = showContentPreview && paletteSectionTarget?.sectionColumn === columnIndex
        const previewBeforeBlockId = isTargetColumn
          ? columnBlocks.find(block => paletteInsertIndex! <= (blockIndexById.get(block.id) ?? 0))?.id || ''
          : ''
        const showPreviewAfterColumn = isTargetColumn && columnBlocks.length > 0 && !previewBeforeBlockId

        return (
          <div
            key={`${lane.id}-${columnIndex}`}
            className={`rstk-section-column ${paletteDragging && lane.section ? 'rstk-section-column-active' : ''} ${isTargetColumn ? 'rstk-section-column-target' : ''}`}
            data-rstk-section-id={lane.section?.id || undefined}
            data-rstk-section-column={lane.section ? columnIndex : undefined}
          >
            {isTargetColumn && columnBlocks.length === 0 && palettePreviewBlock && (
                <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
            )}
            {columnBlocks.map(block => {
              const moveState = getBlockMoveState(block)
              return (
                <React.Fragment key={block.id}>
                  {isTargetColumn && previewBeforeBlockId === block.id && palettePreviewBlock && (
                    <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
                  )}
                  <SortableCanvasBlock
                    block={block}
                    blocks={blocks}
                    index={blockIndexById.get(block.id) ?? 0}
                    selected={selectedBlockId === block.id}
                    site={site}
                    forms={forms}
                    calendars={calendars}
                    pages={pages}
                    activePageId={activePageId}
                    videoActionHoverTargetId={videoActionHoverTargetId}
                    videoActionHiddenNotes={videoActionHiddenNotes}
                    showVideoFormGatePreview={videoFormGatePreviewBlockId === block.id}
                    canMoveUp={moveState.canMoveUp}
                    canMoveDown={moveState.canMoveDown}
                    embeddedFormEditor={embeddedFormEditor}
                    onSelect={() => onSelectBlock(block.id)}
                    onDelete={() => onDeleteBlock(block.id)}
                    onDuplicate={() => onDuplicateBlock(block.id)}
                    onMoveUp={() => onMoveBlock(block.id, 'up')}
                    onMoveDown={() => onMoveBlock(block.id, 'down')}
                    onClearSelection={() => onSelectBlock('')}
                    onPatchBlock={(patch) => onPatchBlock(block.id, patch)}
                    onPatchSettings={(patch) => onPatchBlockSettings(block, patch)}
                    onSave={() => onSaveBlock(block.id)}
                  />
                </React.Fragment>
              )
            })}
            {showPreviewAfterColumn && palettePreviewBlock && (
              <PaletteInsertPreview block={palettePreviewBlock} site={site} forms={forms} calendars={calendars} />
            )}
            {lane.section && columnBlocks.length === 0 && !isTargetColumn && (
              <div className="rstkColumnDropZone">Suelta contenido aquí</div>
            )}
          </div>
        )
      })}
    </div>
  )
}

const SortableLandingSection: React.FC<LandingSectionRenderProps> = ({
  lane,
  blocks,
  blockIndexById,
  selectedBlockId,
  site,
  forms,
  calendars,
  pages,
  activePageId,
  videoActionHoverTargetId = '',
  videoActionHiddenNotes,
  videoFormGatePreviewBlockId = '',
  paletteDragging,
  palettePreviewBlock,
  paletteInsertIndex,
  paletteSectionTarget,
  embeddedFormEditor,
  onSelectBlock,
  onDeleteBlock,
  onDuplicateBlock,
  onMoveBlock,
  getBlockMoveState,
  onPatchBlock,
  onPatchBlockSettings,
  onSaveBlock
}) => {
  const section = lane.section!
  const settings = section.settings || {}
  const selected = selectedBlockId === section.id
  const videoActionHiddenNote = videoActionHiddenNotes?.get(section.id) || ''
  const moveState = getBlockMoveState(section)
  const toolbarPositionClass = moveState.canMoveDown ? '' : 'rstkBlockToolsAbove'
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: section.id,
    animateLayoutChanges: sortableAnimateLayoutChanges,
    transition: sortableTransition
  })
  // Paridad content #14: el publicado pinta cada elemento del heading SOLO si
  // tiene contenido propio. ALLOWED-DIVERGENCE: con la franja seleccionada, el
  // canvas enseña también el que falta (editable) para poder escribirlo.
  const hasHeadingTitle = Boolean(section.content)
  const hasHeadingSubtitle = Boolean(getSettingString(settings, 'subtitle'))
  const hasHeading = hasHeadingTitle || hasHeadingSubtitle || selected

  return (
	    <section
	      ref={setNodeRef}
	      data-rstk-block-id={section.id}
	      data-rstk-block-index={blockIndexById.get(section.id) ?? 0}
	      data-rstk-page-block="true"
	      data-rstk-section-index={blockIndexById.get(section.id) ?? 0}
      data-rstk-section-id={section.id}
      className={getBlockStyleClassName(section, `rstk-section-lane rstkSel ${selected ? 'rstkSelActive' : ''} ${toolbarPositionClass} ${isDragging ? 'rstkSelDragging' : ''} ${videoActionHoverTargetId === section.id ? 'rstkVideoActionHover' : ''} ${videoActionHiddenNote ? 'rstkVideoActionGhost' : ''}`, 'always')}
      style={{
        transform: CSS.Transform.toString(transform),
	        transition: transition || 'transform 520ms cubic-bezier(0.2, 0.8, 0.2, 1)',
        opacity: isDragging ? 0.34 : undefined,
        zIndex: isDragging ? 8 : undefined,
        ...getBlockCanvasStyle(section, { site })
      }}
      onClick={(event) => {
        event.stopPropagation()
        onSelectBlock(section.id)
      }}
    >
      {videoActionHiddenNote && <span className="rstkVideoActionNote">{videoActionHiddenNote}</span>}
      <BlockBackgroundVideo block={section} />
      <div className="rstkBlockTools">
        <button type="button" className="rstkBlockTool rstkBlockToolDrag" {...attributes} {...listeners} aria-label="Reordenar franja">
          <GripVertical size={15} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          disabled={!moveState.canMoveUp}
          onClick={(event) => { event.stopPropagation(); onMoveBlock(section.id, 'up') }}
          aria-label="Subir franja"
        >
          <ArrowUp size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          disabled={!moveState.canMoveDown}
          onClick={(event) => { event.stopPropagation(); onMoveBlock(section.id, 'down') }}
          aria-label="Bajar franja"
        >
          <ArrowDown size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool"
          onClick={(event) => { event.stopPropagation(); onDuplicateBlock(section.id) }}
          onPointerDown={(event) => event.stopPropagation()}
          aria-label="Duplicar contenedor"
          title="Duplicar"
        >
          <Copy size={14} />
        </button>
        <button
          type="button"
          className="rstkBlockTool rstkBlockToolDelete"
          onClick={(event) => { event.stopPropagation(); onDeleteBlock(section.id) }}
          onPointerDown={(event) => event.stopPropagation()}
          aria-label="Eliminar contenedor"
          title="Eliminar"
        >
          <Trash2 size={14} />
        </button>
      </div>
      <div className="rstk-section-inner">
        {hasHeading && (
          <div className="rstk-section-heading">
            {(hasHeadingTitle || selected) && (
              <InlineEditable as="h2" value={section.content} placeholder="Título opcional" onChange={(value) => onPatchBlock(section.id, { content: value })} onCommit={() => onSaveBlock(section.id)} />
            )}
            {(hasHeadingSubtitle || selected) && (
              <InlineEditable as="p" multiline value={getSettingString(settings, 'subtitle')} placeholder="Texto breve opcional" onChange={(value) => onPatchBlockSettings(section, { subtitle: value })} onCommit={() => onSaveBlock(section.id)} />
            )}
          </div>
        )}
        <LandingSectionColumns
          lane={lane}
          blocks={blocks}
          blockIndexById={blockIndexById}
          selectedBlockId={selectedBlockId}
          site={site}
          forms={forms}
          calendars={calendars}
          pages={pages}
          activePageId={activePageId}
          videoActionHoverTargetId={videoActionHoverTargetId}
          videoActionHiddenNotes={videoActionHiddenNotes}
          videoFormGatePreviewBlockId={videoFormGatePreviewBlockId}
	          paletteDragging={paletteDragging}
	          palettePreviewBlock={palettePreviewBlock}
	          paletteInsertIndex={paletteInsertIndex}
	          paletteSectionTarget={paletteSectionTarget}
	          embeddedFormEditor={embeddedFormEditor}
	          onSelectBlock={onSelectBlock}
          onDeleteBlock={onDeleteBlock}
          onDuplicateBlock={onDuplicateBlock}
          onMoveBlock={onMoveBlock}
          getBlockMoveState={getBlockMoveState}
          onPatchBlock={onPatchBlock}
          onPatchBlockSettings={onPatchBlockSettings}
          onSaveBlock={onSaveBlock}
        />
      </div>
    </section>
  )
}

